  }

  /* CRT Effect System */
  .crt-screen {
    position: relative;
    overflow: hidden;
  }

  .crt-screen::after {
    content: " ";
    display: block;
    position: absolute;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    background: rgba(18, 16, 16, 0.1);
