    width: 4px;
  }
  .custom-scrollbar::-webkit-scrollbar-thumb {
    background: rgba(0, 240, 255, 0.1);
  }
}

@keyframes flicker {
  0% { opacity: 0.27; }
  50% { opacity: 0.32; }
  100% { opacity: 0.27; }
}

@keyframes scanline-anim {
  0% { bottom: 100%; }
