'use client';

import React from 'react';
import { Paperclip } from 'lucide-react';
import { ManifestEntity, OMEGA_Manifest } from '@/types/manifest';
import { useAttachmentsLogic } from '@/hooks/manifest-editor/useAttachmentsLogic';
import AttachmentsHeader from '../attachments/AttachmentsHeader';
import AttachmentCard from '../attachments/AttachmentCard';
import InspectorCollapsible from '../shared/InspectorCollapsible';

interface AttachmentsSectionProps {
  item: ManifestEntity;
  manifest: OMEGA_Manifest;
  onUpdate: (updates: Partial<ManifestEntity>) => void;
  availableBinds?: string[];
  onHelp?: (sectionId?: string) => void;
  onOpenConfig?: () => void;
}

export default function AttachmentsSection({ item, manifest, onUpdate, availableBinds = [], onHelp, onOpenConfig }: AttachmentsSectionProps) {
  const { 
    attachments, coreAtt, expandedIdx, setExpandedIdx, 
    addAttachment, removeAttachment, updateAttachment 
  } = useAttachmentsLogic(item, onUpdate);

  const hostType = item.presentation?.component || 'knob';

  return (
    <div className="space-y-4 pt-2">
      <InspectorCollapsible 
        title="Signal Attachments" 
        icon={Paperclip}
      >
        <div className="space-y-4 pt-2">
          <AttachmentsHeader onAdd={addAttachment} onHelp={onHelp} />

          <div className="space-y-2 max-h-[500px] overflow-y-auto pr-1 custom-scrollbar">
            {/* VIRTUAL CORE ITEM */}
            <AttachmentCard 
              att={coreAtt} 
              manifest={manifest}
              hostType={hostType}
              idx="core" 
              isCore={true} 
              isExpanded={expandedIdx === 'core'} 
              onToggle={() => setExpandedIdx(expandedIdx === 'core' ? null : 'core')}
              onRemove={() => {}} 
              onUpdate={updateAttachment} 
              availableBinds={availableBinds}
              onOpenConfig={onOpenConfig}
            />

            {/* LIST OF FRAGMENTS */}
            {attachments.map((att, idx) => (
              <AttachmentCard 
                key={idx}
                att={att} 
                manifest={manifest}
                hostType={hostType}
                idx={idx} 
                isExpanded={expandedIdx === idx} 
                onToggle={() => setExpandedIdx(expandedIdx === idx ? null : idx)}
                onRemove={removeAttachment} 
                onUpdate={updateAttachment} 
                availableBinds={availableBinds}
                onOpenConfig={onOpenConfig}
              />
            ))}
          </div>
        </div>
      </InspectorCollapsible>
    </div>
  );
}

'use client';

import React from 'react';
import { Plus, Layout } from 'lucide-react';
import { LayoutContainer, OMEGA_Manifest } from '@/types/manifest';
import { useContainerState } from '@/hooks/manifest-editor/useContainerState';
import ContainerCard from '../container/ContainerCard';

import InspectorCollapsible from '../shared/InspectorCollapsible';

import IndustrialButton from '../shared/IndustrialButton';
import EmptyState from '../shared/EmptyState';

interface ContainerSectionProps {
  containers: LayoutContainer[];
  manifest: OMEGA_Manifest;
  onAdd: () => void;
  onUpdate: (id: string, updates: Partial<LayoutContainer>) => void;
  onRemove: (id: string) => void;
  highlightPath?: string | null;
}

export default function ContainerSection({
  containers, manifest, onAdd, onUpdate, onRemove, setActiveSection
}: Omit<ContainerSectionProps, 'resolveAsset'> & { setActiveSection?: (s: string) => void }) {
  const { isExpanded, toggleExpand } = useContainerState();

  return (
    <div className="space-y-6 pb-10">
      <InspectorCollapsible 
        title="Layout Architecture" 
        icon={Layout}
      >
        <div className="space-y-4 pt-2">
