  onUpdate: (updates: Partial<OMEGA_Manifest>) => void;
  resolveAsset: (id: string | undefined) => string | undefined;
  activeRackTab: string;
  onOpenConfig?: () => void;
}

type CustomSubTab = 'globals' | 'elements';

