'use client';

import React from 'react';
import { Plus, Settings2, Zap, Layout, Copy, Trash2, Database } from 'lucide-react';
import { OMEGA_Manifest, LayoutContainer, ManifestEntity } from '@/types/manifest';

interface EntityListSectionProps {
  items: ManifestEntity[];
  title: string;
  type: 'control' | 'jack';
  onSelectItem: (id: string) => void;
  onAddEntity: (type: 'control' | 'jack') => void;
  onDuplicateItem: (id: string) => void;
  onRemoveItem: (id: string) => void;
  manifest: OMEGA_Manifest;
  onOpenLibrary?: () => void;
}

import InspectorCollapsible from '../shared/InspectorCollapsible';

import IndustrialButton from '../shared/IndustrialButton';
import EmptyState from '../shared/EmptyState';

/**
 * EntityListSection
 * Centralized list manager for Controls and Signal Ports within the Module Inspector.
 */
export default function EntityListSection({
  items,
  title,
  type,
  onSelectItem,
  onAddEntity,
  onDuplicateItem,
  onRemoveItem,
  manifest,
  onOpenLibrary
}: EntityListSectionProps) {
  const Icon = type === 'control' ? Settings2 : Zap;

  // GROUPING LOGIC (Era 7.2 Container Support)
  const groups = items.reduce((acc: Record<string, ManifestEntity[]>, item) => {
    const gid = item.presentation?.container || 'UNBOUND';
    if (!acc[gid]) acc[gid] = [];
    acc[gid].push(item);
    return acc;
  }, {});

  const containers = manifest?.ui?.layout?.containers || [];

  const groupIds = Object.keys(groups).sort((a, b) => {
    if (a === 'UNBOUND') return 1;
    if (b === 'UNBOUND') return -1;
    return a.localeCompare(b);
  });

  return (
    <div className="space-y-6 pb-20">
      <div className="flex justify-between items-center bg-black/5 p-4 rounded-xs border wb-outline shadow-inner transition-colors duration-500">
        <div className="flex items-center gap-3">
          <Icon className="w-4 h-4 text-primary" />
          <span className="text-[10px] font-black uppercase tracking-[0.2em] wb-text">{title}</span>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => onOpenLibrary?.()}
            className="px-3 py-1.5 rounded-xs border border-accent/30 bg-accent/5 text-accent text-[8px] font-black uppercase hover:bg-accent/10 hover:border-accent transition-all flex items-center gap-1.5"
            title="Browse Universal Cell Library"
          >
            <Database className="w-3 h-3" /> Library
          </button>
          <IndustrialButton 
            label={`Add ${type}`}
            icon={Plus}
            onClick={() => onAddEntity(type)}
            size="sm"
          />
        </div>
      </div>

      <div className="space-y-4">
        {groupIds.map((gid) => {
          const container = containers.find((c: LayoutContainer) => c.id === gid);
          const label = container ? container.label : gid === 'UNBOUND' ? 'UNBOUND ENTITIES' : gid;
          const isLegacy = !container && gid !== 'UNBOUND';

          return (
            <InspectorCollapsible 
              key={gid} 
              title={label} 
              icon={Layout}
            >
              <div className="space-y-1.5 pt-2">
                {groups[gid].map((item) => (
                  <div 
                    key={item.id}
                    onClick={() => onSelectItem(item.id)}
                    className="group relative flex items-center justify-between p-3 rounded-xs border wb-surface-subtle wb-outline hover:border-primary/40 hover:bg-primary/5 hover:shadow-[0_0_20px_rgba(0,0,0,0.1)] transition-all cursor-pointer transition-colors duration-500"
                  >
                    <div className="flex items-center gap-4 overflow-hidden">
                      <div className={`w-1 h-5 rounded-full transition-colors ${isLegacy ? 'bg-amber-500/20 group-hover:bg-amber-500' : 'bg-outline/20 group-hover:bg-primary/40'}`} />
                      <div className="flex flex-col truncate">
                        <div className="flex items-center gap-2">
                          <span className="text-[11px] font-black truncate tracking-tight wb-text group-hover:text-primary transition-colors">{item.label || item.id}</span>
                          {isLegacy && <span className="text-[5px] bg-amber-500/20 px-1 rounded-full text-amber-500 font-bold uppercase">Legacy</span>}
                        </div>
                        <span className="text-[8px] font-mono wb-text-muted uppercase truncate tracking-wider">{item.id}</span>
                      </div>
                    </div>

                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDuplicateItem(item.id); }}
                        className="p-1.5 hover:wb-surface-hover rounded-xs wb-text-muted hover:wb-text transition-colors"
                        title="Duplicate"
                      >
                        <Copy className="w-3.5 h-3.5" />
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); onRemoveItem(item.id); }}
                        className="p-1.5 hover:bg-red-500/10 rounded-xs wb-text-muted hover:text-red-400 transition-colors"
                        title="Delete"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </InspectorCollapsible>
          );
        })}

        {items.length === 0 && (
          <EmptyState 
            message="Registry Empty"
            subMessage={`No ${title.toLowerCase()} defined`}
            icon={Layout}
          />
        )}
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import { Fingerprint } from 'lucide-react';
import { ManifestEntity, OMEGA_Manifest } from '@/types/manifest';
import InspectorCollapsible from '../../shared/InspectorCollapsible';

interface EntityIdentityProps {
  entity: ManifestEntity;
  rootManifest?: OMEGA_Manifest;
  onUpdate: (updates: Partial<ManifestEntity>) => void;
  onHelp?: (id: string) => void;
  isHighlighted: (key: string) => boolean | undefined;
}

export default function EntityIdentity({ entity, rootManifest, onUpdate, onHelp, isHighlighted }: EntityIdentityProps) {
  const getAuthority = () => {
    if (!rootManifest) return null;
    const cIdx = (rootManifest.ui?.controls || []).findIndex(c => c.id === entity.id);
    if (cIdx !== -1) return { type: 'ParamId', value: cIdx };
    const jIdx = (rootManifest.ui?.jacks || []).findIndex(j => j.id === entity.id);
    if (jIdx !== -1) return { type: 'PortId', value: jIdx };
    return null;
  };
  const auth = getAuthority();

  return (
    <InspectorCollapsible 
      title="Entity Identification" 
      icon={Fingerprint}
      onHelp={() => onHelp?.('cells')}
    >
      <div className="space-y-4 pt-2">
         {auth && (
           <div className="flex items-center gap-1 bg-primary/10 border border-primary/20 px-1.5 py-0.5 rounded-full w-fit">
             <span className="text-[6px] text-primary font-black uppercase">{auth.type}:</span>
             <span className="text-[6px] text-primary font-mono font-bold">#{auth.value}</span>
           </div>
         )}

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1.5">
            <label className="text-[7px] font-black wb-text-muted uppercase ml-1 tracking-widest">Canonical ID</label>
            <input 
              type="text" 
              value={entity.id} 
              onChange={(e) => onUpdate({ id: e.target.value })}
              className={`w-full bg-black/5 border ${isHighlighted('id') ? 'border-amber-500 ring-1 ring-amber-500 animate-pulse' : 'wb-outline'} rounded-xs px-3 py-2 text-[10px] font-mono wb-text outline-none focus:border-primary/40 transition-all font-mono [color-scheme:dark]`}
            />
          </div>
          <div className="space-y-1.5">
            <label className="text-[7px] font-black wb-text-muted uppercase ml-1 tracking-widest">Display Label</label>
            <input 
              type="text" 
              value={entity.label || ''} 
              onChange={(e) => onUpdate({ label: e.target.value })}
              className={`w-full bg-black/5 border ${isHighlighted('label') ? 'border-amber-500 ring-1 ring-amber-500 animate-pulse' : 'wb-outline'} rounded-xs px-3 py-2 text-[10px] font-bold wb-text outline-none focus:border-primary/40 transition-all [color-scheme:dark]`}
            />
          </div>
        </div>
      </div>
    </InspectorCollapsible>
  );
}

'use client';

import React from 'react';
import { Ruler } from 'lucide-react';
import { OMEGA_Manifest } from '@/types/manifest';
import InspectorCollapsible from '../../shared/InspectorCollapsible';

interface ModuleMechanicalSpecProps {
  manifest: OMEGA_Manifest;
  onUpdate: (updates: Partial<OMEGA_Manifest>) => void;
  isHighlighted: (key: string) => boolean | undefined;
  onHelp?: (id: string) => void;
}

export default function ModuleMechanicalSpec({ manifest, onUpdate }: Omit<ModuleMechanicalSpecProps, 'isHighlighted' | 'onHelp'>) {
  const metadata = manifest.metadata;
  const rack = (metadata.rack || {}) as { 
    depth?: number; 
    units?: string; 
    power?: { plus12?: number; minus12?: number } 
  };

  const updateRack = (field: string, value: unknown) => {
    onUpdate({ 
      metadata: { 
        ...metadata, 
        rack: { ...rack, [field]: value } 
      } 
    } as Partial<OMEGA_Manifest>);
  };

  return (
    <InspectorCollapsible title="Mechanical Specifications" icon={Ruler}>
      <div className="space-y-4 pt-2">
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1.5">
            <label className="text-[8px] font-bold wb-text-muted uppercase ml-1">Panel Depth (mm)</label>
            <input 
              type="number" 
              value={(rack.depth as number) || 25} 
              onChange={(e) => updateRack('depth', parseInt(e.target.value) || 0)}
              className="w-full wb-surface-subtle border wb-outline rounded-xs px-3 py-2 text-[10px] font-mono wb-text outline-none focus:border-primary/40 transition-all"
            />
          </div>
          <div className="space-y-1.5">
            <label className="text-[8px] font-bold wb-text-muted uppercase ml-1">Mounting Units</label>
            <div className="flex bg-black/20 rounded-xs border wb-outline overflow-hidden">
               {['3U', '1U'].map(u => (
                 <button
                   key={u}
                   onClick={() => updateRack('units', u)}
                   className={`flex-1 py-2 text-[10px] font-black transition-all ${rack.units === u ? 'bg-primary/20 text-primary' : 'wb-text-muted hover:text-white'}`}
                 >
                   {u}
                 </button>
               ))}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 pt-1">
           <div className="space-y-1.5">
              <label className="text-[8px] font-bold wb-text-muted uppercase ml-1">+12V (mA)</label>
              <input 
                type="number" 
                value={(rack.power?.plus12 as number) || 0} 
                onChange={(e) => updateRack('power', { ...(rack.power || {}), plus12: parseInt(e.target.value) || 0 })}
                className="w-full wb-surface-subtle border wb-outline rounded-xs px-3 py-2 text-[10px] font-mono wb-text outline-none focus:border-primary/40 transition-all"
              />
           </div>
           <div className="space-y-1.5">
              <label className="text-[8px] font-bold wb-text-muted uppercase ml-1">-12V (mA)</label>
              <input 
                type="number" 
                value={(rack.power?.minus12 as number) || 0} 
                onChange={(e) => updateRack('power', { ...(rack.power || {}), minus12: parseInt(e.target.value) || 0 })}
                className="w-full wb-surface-subtle border wb-outline rounded-xs px-3 py-2 text-[10px] font-mono wb-text outline-none focus:border-primary/40 transition-all"
              />
           </div>
        </div>
      </div>
    </InspectorCollapsible>
  );
}

