    );
  }

  const manifest = item as OMEGA_Manifest;

  return (
    <div className="space-y-10 pt-2 pb-10">
      <ModuleSignature 
        manifest={manifest} 
        onUpdate={(u: Partial<OMEGA_Manifest>) => onUpdate(u)} 
        onHelp={onHelp} 
        isHighlighted={isHighlighted} 
        resolveAsset={resolveAsset}
      />

      <ModuleSkinSelector 
        manifest={manifest} 
        onUpdate={(u: Partial<OMEGA_Manifest>) => onUpdate(u)} 
      />

      <ModulePlaneSelector 
        manifest={manifest}
        onUpdate={(u: Partial<OMEGA_Manifest>) => onUpdate(u)}
      />

      <ModuleTaxonomy 
        manifest={manifest} 
        onUpdate={(u: Partial<OMEGA_Manifest>) => onUpdate(u)} 
        isHighlighted={isHighlighted} 
      />

      <ModuleMechanicalSpec 
        manifest={manifest} 
        onUpdate={(u: Partial<OMEGA_Manifest>) => onUpdate(u)} 
      />
    </div>
  );
}

