      {/* CONTENT AREA */}
      <div className="flex-1 overflow-y-auto custom-scrollbar pr-1">
        {activeSubTab === 'infra' && (
          <ContainerSection 
            containers={manifest.ui.layout?.containers || []} 
            manifest={manifest} 
            onAdd={addContainer} 
            onUpdate={updateContainer} 
            onRemove={removeContainer} 
            highlightPath={highlightPath} 
            setActiveSection={setActiveSection}
          />
        )}

        {activeSubTab === 'controls' && (
          <EntityListSection 
            items={manifest.ui?.controls || []} 
            title="Interactive Controls" 
            type="control" 
            onSelectItem={onSelectItem} 
            onAddEntity={onAddEntity} 
            onDuplicateItem={onDuplicateItem} 
            onRemoveItem={onRemoveItem} 
            manifest={manifest} 
          />
        )}

        {activeSubTab === 'ports' && (
          <EntityListSection 
            items={manifest.ui?.jacks || []} 
            title="Signal Ports / Jacks" 
            type="jack" 
            onSelectItem={onSelectItem} 
            onAddEntity={onAddEntity} 
            onDuplicateItem={onDuplicateItem} 
            onRemoveItem={onRemoveItem} 
            manifest={manifest} 
          />
        )}

        {activeSubTab === 'routing' && (
          <ModulationSection 
            manifest={manifest} 
            onAdd={onAddModulation} 
            onRemove={onRemoveModulation} 
            onUpdate={onUpdateModulation} 
            onOpenModGrid={onOpenModGrid} 
          />
        )}

        {activeSubTab === 'assets' && extraResources && (
          <ResourceSection 
            resources={extraResources} 
            onTriggerUpload={onTriggerUpload || (() => {})} 
            onRemove={onRemoveResource || (() => {})} 
          />
        )}
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { Image as ImageIcon, Plus, Trash2, FileImage, Globe, ShieldCheck, Folder, ChevronLeft } from 'lucide-react';
import Image from 'next/image';
import { ExtraResource } from '@/types/manifest';
import InspectorCollapsible from '../shared/InspectorCollapsible';
import IndustrialButton from '../shared/IndustrialButton';
import EmptyState from '../shared/EmptyState';
import InfoBlock from '../shared/InfoBlock';

interface ResourceSectionProps {
  resources: ExtraResource[];
  onTriggerUpload: () => void;
  onRemove?: (name: string) => void;
}

interface ResourceItemProps {
  res: ExtraResource;
  idx: number;
  onRemove?: (name: string) => void;
}

const ResourceItem = React.memo(({ res, idx, onRemove }: ResourceItemProps) => {
  const [previewUrl, setPreviewUrl] = React.useState<string | null>(null);

  React.useEffect(() => {
    if (!res.type.startsWith('image/')) return;

    const blob = new Blob([res.data], { type: res.type });
    const url = URL.createObjectURL(blob);
    const timer = setTimeout(() => setPreviewUrl(url), 0);

    return () => {
      clearTimeout(timer);
      URL.revokeObjectURL(url);
    };
  }, [res.data, res.type]);

  return (
    <motion.div 
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: idx * 0.05 }}
      className="group p-3 bg-white/2 border border-outline/10 rounded-sm hover:border-primary/20 transition-all flex items-center justify-between"
    >
      <div className="flex items-center gap-3">
