ResourceItem.displayName = 'ResourceItem';

export default function ResourceSection({ resources, onTriggerUpload, onRemove }: ResourceSectionProps) {
  const [currentPath, setCurrentPath] = React.useState<string | null>(null);

  // VIRTUAL FILE SYSTEM LOGIC
  const folders = React.useMemo(() => {
    const map = new Map<string, ExtraResource[]>();
    resources.forEach(res => {
      const parts = res.name.split('/');
      if (parts.length > 1) {
        const folderName = parts[0];
        if (!map.has(folderName)) map.set(folderName, []);
        map.get(folderName)?.push(res);
      } else {
        if (!map.has('root')) map.set('root', []);
        map.get('root')?.push(res);
      }
    });
    return map;
  }, [resources]);


  const rootItems = folders.get('root') || [];

  return (
    <div className="space-y-4 pt-2">
      <InspectorCollapsible 
        title="Industrial Asset Registry" 
        icon={ImageIcon}
      >
        <div className="space-y-4 pt-2">
          {/* VFS BREADCRUMBS & OPS */}
          <div className="flex items-center justify-between mb-4 px-1">
            <div className="flex items-center gap-2">
               {currentPath && (
                 <button 
                   onClick={() => setCurrentPath(null)}
                   className="p-1.5 bg-accent/5 border border-accent/20 rounded-xs transition-all hover:bg-accent/10 flex items-center gap-1 text-[8px] font-black uppercase text-accent group"
                 >
                   <ChevronLeft className="w-3 h-3 group-hover:-translate-x-0.5 transition-transform" />
                   Root
                 </button>
               )}
               <div className="flex items-center gap-1.5 text-[9px] font-black uppercase tracking-[0.2em] text-foreground/40">
                  <Globe className="w-3 h-3 opacity-20" />
                  <span className="opacity-40">Registry</span>
                  {currentPath && (
                    <>
                      <span className="opacity-10">/</span>
                      <span className="text-accent bg-accent/10 px-1.5 py-0.5 rounded-xs">{currentPath}</span>
                    </>
                  )}
               </div>
            </div>
            <IndustrialButton 
              label="Ingest Asset"
              icon={Plus}
              onClick={onTriggerUpload}
              variant="primary"
              size="sm"
            />
          </div>

          <div className="grid grid-cols-1 gap-2 px-1">
            {resources.length === 0 ? (
              <EmptyState 
                message="No Assets Ingested"
                subMessage="Resources will be categorized in the VFS"
                icon={FileImage}
              />
            ) : (
              <>
                {/* INDUSTRIAL FOLDERS */}
                {!currentPath && Array.from(folders.keys()).filter(k => k !== 'root').map(folderName => (
                  <button
                    key={folderName}
                    onClick={() => setCurrentPath(folderName)}
                    className="p-3 bg-black/40 border wb-outline rounded-sm hover:border-accent/40 transition-all flex items-center justify-between group"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-accent/5 border border-accent/20 rounded-xs flex items-center justify-center">
                         <Folder className="w-5 h-5 text-accent group-hover:scale-110 transition-transform" />
                      </div>
                      <div className="text-left space-y-0.5">
                        <p className="text-[10px] font-black text-foreground/80 uppercase tracking-widest">{folderName}</p>
                        <p className="text-[7px] font-bold text-accent/40 uppercase tracking-tighter">
                          {folders.get(folderName)?.length} Industrial Objects
                        </p>
                      </div>
                    </div>
                  </button>
                ))}

                {/* VIRTUAL ITEMS */}
                {currentPath ? (
                  folders.get(currentPath)?.map((res, idx) => (
                    <ResourceItem 
                      key={res.name} 
                      res={res} 
                      idx={idx} 
                      onRemove={onRemove} 
                    />
                  ))
                ) : (
                  rootItems.map((res, idx) => (
                    <ResourceItem 
                      key={res.name} 
                      res={res} 
                      idx={idx} 
                      onRemove={onRemove} 
                    />
                  ))
                )}
              </>
            )}
          </div>
        </div>
      </InspectorCollapsible>

      <InfoBlock 
        title="Industrial Storage"
        icon={Globe}
        message="Governance Rule: Categorize assets using '/' in filenames (e.g. 'branding/logo.svg')."
        variant="muted"
        className="mt-6"
      />
    </div>
  );
}

'use client';

import React from 'react';
import { Move, Grid3X3, Layout, Info } from 'lucide-react';
import { ManifestEntity, LayoutContainer } from '@/types/manifest';
import ContainerSelector from '../ContainerSelector';
import InspectorCollapsible from '../shared/InspectorCollapsible';
import InfoBlock from '../shared/InfoBlock';

import { getElementDefinition } from '@/omega-ui-core/governance/ElementCatalog';

interface SpatialSectionProps {
  item: ManifestEntity;
  onUpdate: (updates: Partial<ManifestEntity>) => void;
  onHelp?: (sectionId?: string) => void;
  highlightPath?: string | null;
  containers?: LayoutContainer[];
}

export default function SpatialSection({ item, onUpdate, onHelp, highlightPath, containers = [] }: SpatialSectionProps) {
  const componentType = item.presentation?.component || 'knob';
  const elementDef = getElementDefinition(componentType);
  const pos = item.pos || { x: 0, y: 0 };
  const pres = item.presentation || {};
  const isHighlighted = (key: string) => highlightPath?.includes(key);

  const canMove = !elementDef || elementDef.capabilities.includes('position');
  const canScale = !elementDef || elementDef.capabilities.includes('size');

  return (
    <div className="space-y-4 pt-2">
      <ContainerSelector 
        item={item} 
        onUpdate={onUpdate} 
        containers={containers} 
        onHelp={onHelp} 
        highlightPath={highlightPath} 
      />

      {/* COORDINATES */}
      {canMove && (
        <InspectorCollapsible 
          title="Absolute Coordinates" 
          icon={Move}
          onHelp={() => onHelp?.('spatial')}
        >
          <div className="grid grid-cols-2 gap-4 pt-2">
            <div className="space-y-1.5">
              <label className={`text-[8px] uppercase font-bold tracking-tighter flex items-center gap-1 transition-colors ${isHighlighted('pos') ? 'text-amber-500' : 'text-foreground/60'}`}>
                <span>Axis X (Horizontal)</span>
              </label>
              <input 
                type="number" 
                value={pos.x || 0} 
                onChange={(e) => onUpdate({ pos: { ...pos, x: parseFloat(e.target.value) } })}
                className={`w-full bg-black/40 border ${isHighlighted('pos') ? 'border-amber-500 ring-1 ring-amber-500 animate-pulse' : 'border-outline'} rounded-sm p-2 text-[11px] font-mono text-foreground outline-none focus:border-primary/40 transition-all transition-colors duration-500`}
              />
            </div>
            <div className="space-y-1.5">
              <label className={`text-[8px] uppercase font-bold tracking-tighter flex items-center gap-1 transition-colors ${isHighlighted('pos') ? 'text-amber-500' : 'text-foreground/60'}`}>
                <span>Axis Y (Vertical)</span>
              </label>
              <input 
                type="number" 
                value={pos.y || 0} 
                onChange={(e) => onUpdate({ pos: { ...pos, y: parseFloat(e.target.value) } })}
                className={`w-full bg-black/40 border ${isHighlighted('pos') ? 'border-amber-500 ring-1 ring-amber-500 animate-pulse' : 'border-outline'} rounded-sm p-2 text-[11px] font-mono text-foreground outline-none focus:border-primary/40 transition-all transition-colors duration-500`}
              />
            </div>
          </div>
        </InspectorCollapsible>
      )}

      {/* GRID LOGIC (Era 6 Compatibility) */}
      {canScale && (
        <InspectorCollapsible 
          title="Grid Dimensionality" 
          icon={Grid3X3}
          onHelp={() => onHelp?.('dimensiones')}
        >
          <div className="space-y-1.5 pt-2">
            <label className="text-[8px] text-foreground/60 uppercase font-bold tracking-tighter">
              Column Span (Rack Width)
            </label>
            <select 
              value={pres.colSpan || 1} 
              onChange={(e) => onUpdate({ presentation: { ...pres, colSpan: parseInt(e.target.value) } })}
              className="w-full bg-black/40 border border-outline rounded-sm p-2 text-[10px] font-bold text-foreground outline-none transition-colors duration-500 [color-scheme:dark]"
            >
              <option value={1}>1 Column (Standard)</option>
              <option value={2}>2 Columns (Wide)</option>
              <option value={3}>3 Columns (Full Width)</option>
            </select>
          </div>
        </InspectorCollapsible>
      )}

      {/* NO SPATIAL GOVERNANCE WARNING */}
      {!canMove && !canScale && (
        <div className="p-4 bg-white/5 border border-dashed wb-outline rounded-xs flex items-center gap-3 opacity-40">
           <Layout className="w-5 h-5" />
           <p className="text-[7px] wb-text-muted font-bold uppercase leading-tight italic">
              Spatial governance is locked for this element. Its position and size are managed by the internal rack engine.
           </p>
        </div>
      )}

      <InfoBlock 
        title="Industrial Note"
        icon={Info}
        message="Era 7.2 enforces strict architectural framing. Use containers to define columns and sections for studio parity."
        variant="primary"
        className="mt-6"
      />
    </div>
  );
}

