                         <span className="text-[6px] font-mono text-primary">{(values[corner.key] as number) ?? values.rounding ?? 0}px</span>
                      </div>
                      <input 
                        type="range" min="0" max="100" step="1"
                        value={(values[corner.key] as number) ?? values.rounding ?? 0}
