            <div className="flex items-center gap-1">
                <div className="w-1 h-1 rounded-full bg-accent animate-pulse" />
                <span className="text-[6px] text-accent uppercase font-black">Sys_Ready</span>
            </div>
        </div>
      </div>
    </div>
  );
}

