interface WorkbenchInspectorProps {
  isVisible: boolean;
  isLiveMode: boolean;
  uiTheme: 'dark' | 'light';
  manifest: OMEGA_Manifest;
  selectedItem: ManifestEntity | OMEGA_Manifest | null;
  selectedItemId: string | null;
  highlightPath: string | null;
  availableBinds: string[];
  extraResources: ExtraResource[];
  audit: AuditResult;
  onUpdateItem: (id: string, updates: Partial<ManifestEntity>) => void;
  onUpdateManifest: (updates: Partial<OMEGA_Manifest>) => void;
  onSelectItem: (id: string | null) => void;
  onAddEntity: (type: 'control' | 'jack') => void;
  onDuplicateItem: (id: string) => void;
  onRemoveItem: (id: string) => void;
  onAddModulation: (mod: OMEGA_Modulation) => void;
  onRemoveModulation: (id: string) => void;
  onUpdateModulation: (id: string, updates: Partial<OMEGA_Modulation>) => void;
  onOpenModGrid: () => void;
  addContainer: (c?: Partial<LayoutContainer>) => void;
  updateContainer: (id: string, updates: Partial<LayoutContainer>) => void;
  removeContainer: (id: string) => void;
  onHelp: (sectionId?: string) => void;
  onRemoveResource: (name: string) => void;
  resolveAsset: (id: string | undefined) => string | undefined;
  onTriggerUpload: (id: string) => void;
  activeTab: string;
  onOpenConfig?: () => void;
  onOpenLibrary?: () => void;
}

export function WorkbenchInspector({
  isVisible,
  isLiveMode,
  uiTheme,
  manifest,
  selectedItem,
  selectedItemId,
  highlightPath,
  availableBinds,
  extraResources,
  onUpdateItem,
  onUpdateManifest,
  onSelectItem,
  onAddEntity,
  onDuplicateItem,
  onRemoveItem,
  onAddModulation,
  onRemoveModulation,
  onUpdateModulation,
  onOpenModGrid,
  addContainer,
  updateContainer,
  removeContainer,
  onHelp,
  onRemoveResource,
  resolveAsset,
  activeTab,
  onTriggerUpload,
  onOpenConfig,
  onOpenLibrary
}: WorkbenchInspectorProps) {

  // ASEPTIC HANDLERS
  const handleUpdate = (updates: Partial<OMEGA_Manifest> | Partial<ManifestEntity>) => {
    if (selectedItemId) {
      onUpdateItem(selectedItemId, updates);
      if (updates.id && updates.id !== selectedItemId) {
        onSelectItem(updates.id);
      }
    } else {
      onUpdateManifest(updates as Partial<OMEGA_Manifest>);
    }
  };

  return (
    <AnimatePresence>
      {isVisible && !isLiveMode && (
        <motion.aside 
          key="inspector" 
          initial={{ x: 600 }} 
          animate={{ x: 0 }} 
          exit={{ x: 600 }} 
          className="w-[600px] shrink-0 h-full border-l wb-outline transition-colors duration-500"
        >
          <PropertyPanel 
            uiTheme={uiTheme} 
            manifest={manifest} 
            item={selectedItem!} 
            highlightPath={highlightPath}
            onUpdate={handleUpdate}
            onClose={() => onSelectItem(null)} 
            availableBinds={availableBinds}
            onSelectItem={onSelectItem} 
            onAddEntity={onAddEntity} 
            onDuplicateItem={onDuplicateItem} 
            onRemoveItem={onRemoveItem}
            onAddModulation={onAddModulation} 
            onRemoveModulation={onRemoveModulation} 
            onUpdateModulation={onUpdateModulation} 
            onOpenModGrid={onOpenModGrid}
            addContainer={addContainer} 
            updateContainer={updateContainer} 
            removeContainer={removeContainer}
            onHelp={onHelp} 
            extraResources={extraResources} 
            onRemoveResource={onRemoveResource}
            resolveAsset={resolveAsset}
            activeTab={activeTab}
            onTriggerUpload={onTriggerUpload}
            onOpenConfig={onOpenConfig}
            onOpenLibrary={onOpenLibrary}
          />
        </motion.aside>
      )}
    </AnimatePresence>
  );
}

