export default function Stepper({ type, value, variant, onValueChange, onClick, text, manifest, item }: StepperProps) {
  const { colors, resolveFont, style, physics, allVars } = useDesignTokens(manifest, item);

  const parts = (variant || 'B_cyan').split('_');
  const size = parts[0] || 'B';

  const dims: Record<string, number> = { A: 24, B: 18, C: 14, D: 12 };
  const d = dims[size] || 18;

  const font = style?.resolvedFont || resolveFont('labels');

  const handlePointerDown = (e: React.PointerEvent) => {
    e.stopPropagation();
    if (type === 'push') onValueChange(1);
    if (onClick) onClick();
  };

  const handlePointerUp = () => {
    if (type === 'push') onValueChange(0);
  };

  return (
    <div 
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      className={`bg-black/60 border rounded-xs flex items-center justify-center cursor-pointer active:scale-95 transition-all overflow-hidden ${value > 0.5 ? 'border-primary/40' : ''}`} 
      style={{ 
        ...allVars,
        width: `${d}px`, 
        height: `${d}px`,
        backgroundColor: colors.surface,
        borderColor: value > 0.5 ? colors.accent : colors.weak,
        filter: physics.filter
      } as React.CSSProperties}
    >
      {text ? (
        <span 
          style={{ 
            color: value > 0.5 ? colors.accent : colors.text, 
            fontSize: `${d/2}px`,
            fontFamily: font
          }} 
          className="font-mono font-black select-none pointer-events-none opacity-80"
        >
          {text}
        </span>
      ) : (
        <div 
          className="w-1.5 h-1.5 rounded-full" 
          style={{ 
            backgroundColor: value > 0.5 ? colors.accent : colors.weak, 
            boxShadow: value > 0.5 ? `0 0 10px ${colors.accent}` : 'none',
            opacity: value > 0.5 ? 1 : 0.2
          }} 
        />
      )}
    </div>
  );
}

import { OMEGA_Manifest, ManifestEntity } from '@/types/manifest';
import { useDesignTokens } from '@/hooks/manifest-editor/useDesignTokens';

interface SwitchProps {
  value: number;
  variant: string;
  onValueChange: (val: number) => void;
  onClick?: () => void;
  manifest: OMEGA_Manifest;
  item?: ManifestEntity;
  isMain?: boolean;
}

export default function Switch({ value, variant, onValueChange, onClick, manifest, item }: SwitchProps) {
  const { colors, physics, allVars } = useDesignTokens(manifest, item);

  const parts = (variant || 'B_cyan').split('_');
  const size = parts[0] || 'B';
  const colorId = parts[1] || 'cyan';

  const handleToggle = (e: React.MouseEvent) => {
    e.stopPropagation();
    onValueChange(value > 0.5 ? 0 : 1);
    if (onClick) onClick();
  };

  return (
    <div 
      onClick={handleToggle}
      className={`switch-container size-${size} color-${colorId}`}
      style={{
        ...allVars,
        backgroundColor: colors.surface,
        borderColor: colors.weak,
        filter: physics.filter
      } as React.CSSProperties}
    >
      <div className={`sw-led ${value < 0.5 ? 'active' : ''}`} style={{ backgroundColor: value < 0.5 ? colors.accent : undefined }} />
      <div className={`sw-led ${value >= 0.5 ? 'active' : ''}`} style={{ backgroundColor: value >= 0.5 ? colors.accent : undefined }} />
    </div>
  );
}

'use client';

import React, { useEffect, useRef, useState } from 'react';
import { clsx } from 'clsx';

import { OMEGA_Manifest, ManifestEntity } from '@/types/manifest';
import { useDesignTokens } from '@/hooks/manifest-editor/useDesignTokens';

interface TerminalProps {
  text?: string;
  variant?: 'phosphor' | 'amber' | 'cyan';
  width?: number;
  height?: number;
  className?: string;
  maxLines?: number;
  color?: string;
  fontFamily?: string;
  manifest: OMEGA_Manifest;
  item?: ManifestEntity;
}

/**
 * Terminal
 * OMEGA Canonical Log/Monitor Primitive (Era 7.2.3)
 */
export default function Terminal({
  text,
  variant = 'phosphor',
  width = 140,
  height = 90,
  className,
  maxLines = 50,
  color,
  fontFamily,
  manifest,
  item
}: TerminalProps) {
  const { physics, allVars } = useDesignTokens(manifest, item);
  const [lines, setLines] = useState<string[]>([]);
  const [prevText, setPrevText] = useState<string | undefined>(text);
  const containerRef = useRef<HTMLDivElement>(null);

  if (text !== prevText) {
    setPrevText(text);
    if (text) {
      setLines(prev => {
        const next = [...prev, text];
        if (next.length > maxLines) return next.slice(next.length - maxLines);
        return next;
      });
    }
  }

  // Auto-scroll logic
  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [lines]);

  return (
    <div 
      className={clsx('terminal-display', `variant-${variant}`, className)}
      style={{ 
        ...allVars,
        '--terminal-width': `${width}px`, 
        '--terminal-height': `${height}px`,
        color: color,
        fontFamily: fontFamily,
        filter: physics.filter
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any}
    >
      <div ref={containerRef} className="terminal-container">
        {lines.length === 0 && (
          <div className="terminal-line opacity-20 italic">No signal...</div>
        )}
        {lines.map((line, i) => (
          <div key={i} className="terminal-line">
            {`> ${line}`}
          </div>
        ))}
      </div>
    </div>
  );
}

import React from 'react';
import { motion } from 'framer-motion';
import { OMEGA_Manifest, ManifestEntity, TabName } from '@/types/manifest';

interface ModulationCablesProps {
  manifest: OMEGA_Manifest;
  allElements: ManifestEntity[];
  activeTab: TabName;
}

/**
 * ModulationCables (v7.2.3)
 * Renders SVG patch cables to visualize signal modulations.
 */
export const ModulationCables = ({ manifest, allElements, activeTab }: ModulationCablesProps) => {
  if (activeTab !== 'MOD') return null;

  return (
    <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible z-20">
      {(manifest.modulations || []).map((mod) => {
        const src = allElements.find(e => e.id === mod.source);
        const tgt = allElements.find(e => e.id === mod.target);
        if (!src || !tgt) return null;

        return (
          <g key={mod.id}>
            <motion.path
              initial={{ pathLength: 0, opacity: 0 }}
              animate={{ pathLength: 1, opacity: 0.6 }}
              d={`M ${src.pos.x * 1.5} ${src.pos.y * 1.5} C ${(src.pos.x + 20) * 1.5} ${src.pos.y * 1.5}, ${(tgt.pos.x - 20) * 1.5} ${tgt.pos.y * 1.5}, ${tgt.pos.x * 1.5} ${tgt.pos.y * 1.5}`}
              fill="none"
              stroke="cyan"
              strokeWidth="2"
              strokeDasharray="4 4"
              className="drop-shadow-[0_0_8px_rgba(0,255,255,0.8)]"
            />
            <motion.circle 
              cx={src.pos.x * 1.5} cy={src.pos.y * 1.5} r="3" fill="cyan" 
              animate={{ r: [3, 5, 3] }} transition={{ duration: 1, repeat: Infinity }}
            />
            <motion.circle cx={tgt.pos.x * 1.5} cy={tgt.pos.y * 1.5} r="3" fill="cyan" />
          </g>
        );
      })}
    </svg>
  );
};

import React from 'react';
import { motion } from 'framer-motion';
import { LayoutContainer, OMEGA_Manifest, ManifestEntity } from '@/types/manifest';
import { AuditResult } from '@/services/auditService';
import { ValidationIssue } from '@/types/validation';
import IndustrialContainer from '../shared/IndustrialContainer';

interface RackContainerProps {
  container: LayoutContainer;
  isSelected: boolean;
  activeContainers: Record<string, number>;
  audit: AuditResult;
  skin: string;
  rackWidthPx: number;
  isLiveMode?: boolean;
  resolveAsset?: (ref: string | undefined) => string | undefined;
  manifest?: OMEGA_Manifest;
}

import { useDesignTokens } from '@/hooks/manifest-editor/useDesignTokens';

const RackContainerBase = ({ 
  container, 
  isSelected, 
  activeContainers, 
  audit, 
  skin, 
  rackWidthPx,
  resolveAsset,
  manifest
}: RackContainerProps) => {
  const c = container;
  const isCollapsed = c.collapsed;

  // INDUSTRIAL TOKEN RESOLUTION
  useDesignTokens(manifest as OMEGA_Manifest, c as unknown as ManifestEntity);

  const resolveWidth = (w: string | number): number => {
    if (typeof w === 'number') return w * 1.5;
    switch (w) {
      case 'full': return rackWidthPx;
      case '3/4': return rackWidthPx * 0.75;
      case '2/3': return rackWidthPx * 0.667;
      case '1/2': return rackWidthPx * 0.5;
      case '1/3': return rackWidthPx * 0.333;
      case '1/4': return rackWidthPx * 0.25;
      default: return (parseInt(w) || 100) * 1.5;
    }
  };

  const cw = resolveWidth(c.size.w);
  const ch = isCollapsed ? 30 : (c.size.h * 1.5);
  const cx = c.pos.x * 1.5;
  const cy = c.pos.y * 1.5;
  const containerIssues = React.useMemo(() => 
    audit?.issues?.filter((i: ValidationIssue) => i.path.includes(c.id) || i.message.includes(`'${c.id}'`)) || [],
    [audit.issues, c.id]
  );

  const hasIntegrityError = containerIssues.some(i => i.keyword === 'era7_integrity');

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ 
        opacity: 1,
        boxShadow: isSelected 
          ? '0 0 40px rgba(0,240,255,0.15)' 
          : (hasIntegrityError ? '0 0 20px rgba(255,62,62,0.1)' : '0 0 0px rgba(0,0,0,0)'),
      }}
      className="absolute pointer-events-none"
      style={{ 
        left: cx, 
        top: cy, 
        width: cw, 
        height: ch,
        zIndex: isSelected ? 5 : 0,
      }}
    >
      <IndustrialContainer 
        container={c}
        manifest={manifest as OMEGA_Manifest}
        resolveAsset={resolveAsset}
        isSelected={isSelected}
        isError={hasIntegrityError}
        className={`w-full h-full container-${skin}`}
        style={{ '--omega-z-index': c.zIndex ?? (isSelected ? 10 : 1) } as React.CSSProperties}
      />

      {/* ACTIVITY HEATMAP PULSE */}
      <motion.div 
        animate={{ 
          opacity: (activeContainers[c.id] || 0) * 0.2 + 0.05,
          scale: 1 + (activeContainers[c.id] || 0) * 0.01
        }}
        transition={{ type: 'spring', damping: 20 }}
        className={`absolute inset-0 rounded-xs pointer-events-none ${hasIntegrityError ? 'bg-red-500/20' : 'bg-primary/20'}`}
        style={{ borderRadius: c.rounding ? `${c.rounding}px` : 'var(--omega-rounding)' }}
      />
    </motion.div>
  );
};

export const RackContainer = React.memo(RackContainerBase, (prev, next) => {
  return (
    prev.container.id === next.container.id &&
    prev.container.collapsed === next.container.collapsed &&
    JSON.stringify(prev.container.pos) === JSON.stringify(next.container.pos) &&
    JSON.stringify(prev.container.size) === JSON.stringify(next.container.size) &&
    prev.isSelected === next.isSelected &&
    prev.skin === next.skin &&
    prev.isLiveMode === next.isLiveMode &&
    prev.container.asset === next.container.asset &&
    prev.container.color === next.container.color &&
    prev.container.rounding === next.container.rounding &&
    prev.container.borderWidth === next.container.borderWidth &&
    prev.container.font === next.container.font &&
    prev.container.fontSize === next.container.fontSize &&
    prev.container.fontColor === next.container.fontColor &&
    prev.container.zIndex === next.container.zIndex &&
    JSON.stringify(prev.container.style) === JSON.stringify(next.container.style) &&
    prev.activeContainers[prev.container.id] === next.activeContainers[next.container.id] &&
    prev.audit.issues.length === next.audit.issues.length &&
    JSON.stringify(prev.manifest?.ui?.styles) === JSON.stringify(next.manifest?.ui?.styles) &&
    JSON.stringify(prev.manifest?.ui?.typography) === JSON.stringify(next.manifest?.ui?.typography)
  );
});

import React from 'react';
import { motion, useDragControls } from 'framer-motion';
import { Move, AlertCircle } from 'lucide-react';
import { ManifestEntity, OMEGA_Manifest } from '@/types/manifest';
import { AuditResult } from '@/services/auditService';
import PrimitiveFactory from '../primitives/PrimitiveFactory';

interface RackEntityProps {
  item: ManifestEntity & { isJack?: boolean };
  rackRef: React.RefObject<HTMLDivElement | null>;
  zoom: number;
  isLiveMode: boolean;
  selectedItemId: string | null;
  onSelectItem: (id: string | null) => void;
  onUpdateItem: (id: string, updates: Partial<ManifestEntity>) => void;
  runtimeValue: number;
  steps: number;
  onPortClick: (id: string) => void;
  audit: AuditResult;
  skin: string;
  resolveAsset?: (ref: string | undefined) => string | undefined;
  manifest: OMEGA_Manifest;
}

/**
 * RackEntity (v7.2.3)
 * Represents an individual draggable control or jack within the rack.
 * Memoized for high-performance industrial rendering (60 FPS).
 */
const RackEntityBase = ({ 
  item, 
  rackRef, 
  zoom, 
  isLiveMode, 
  selectedItemId, 
  onSelectItem, 
  onUpdateItem, 
  runtimeValue, 
  steps, 
  onPortClick, 
  audit,
  skin,
  resolveAsset,
  manifest
}: RackEntityProps) => {
  const dragControls = useDragControls();
  const isSelected = selectedItemId === item.id && !isLiveMode;
  const isJack = item.isJack || item.presentation?.component === 'port' || item.type === 'port';

  const handleClick = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (isLiveMode && isJack) {
      onPortClick(item.id);
    } else {
      onSelectItem(item.id);
    }
  };

  // ORPHAN DETECTION (ERA 4 GOVERNANCE)
  const hasRole = !!item.role;

  const itemIssues = React.useMemo(() => 
    audit.issues.filter(issue => issue.path.includes(item.id) || issue.message.includes(`'${item.id}'`)),
    [audit.issues, item.id]
  );

  const isOrphan = itemIssues.length > 0 || !hasRole;

  return (
    <motion.div
      drag={!isLiveMode} 
      dragControls={dragControls} 
      dragMomentum={false} 
      dragConstraints={rackRef} 
      dragElastic={0}
      onDragEnd={(_, info) => { 
        if (rackRef.current) { 
          const rect = rackRef.current.getBoundingClientRect(); 
          onUpdateItem(item.id, { 
            pos: { 
              x: Math.round((info.point.x - rect.left) / (1.5 * zoom)), 
              y: Math.round((info.point.y - rect.top) / (1.5 * zoom)) 
            } 
          }); 
        } 
      }}
      animate={{ x: (item.pos?.x || 0) * 1.5, y: (item.pos?.y || 0) * 1.5 }}
      transition={{ type: 'tween', duration: 0 }}
      style={{ 
        position: 'absolute', 
        left: 0, 
        top: 0, 
        width: 0, 
        height: 0, 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center', 
        translateX: "-50%",
        translateY: "-50%",
        zIndex: isSelected ? 50 : 20, 
        cursor: isLiveMode ? 'pointer' : 'grab' 
      }}
      onClick={handleClick}
    >
      <div className="relative w-full h-full flex items-center justify-center group">
        {/* ORPHAN WARNING AURA */}
        {isOrphan && (
          <>
            <motion.div 
              animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.6, 0.3] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="absolute -inset-2 bg-red-500/20 rounded-full blur-xl pointer-events-none"
            />
            <div className="absolute bottom-full mb-4 opacity-0 group-hover:opacity-100 transition-opacity duration-200 pointer-events-none z-[100]">
               <div className="bg-red-600 text-white px-3 py-1.5 rounded-xs shadow-2xl border border-red-400/40 flex flex-col gap-1 min-w-[140px]">
                  <div className="flex items-center gap-2 border-b border-white/20 pb-1">
                     <AlertCircle className="w-3 h-3" />
                     <span className="text-[8px] font-black uppercase tracking-widest">Orphan Detected</span>
                  </div>
                  <span className="text-[7px] font-bold uppercase leading-tight whitespace-pre-line">
                    {itemIssues.map(i => `• ${i.message}`).join('\n')}
                    {!hasRole && '• Missing Registry Role'}
                  </span>
               </div>
               <div className="w-2 h-2 bg-red-600 rotate-45 mx-auto -mt-1 border-r border-b border-red-400/40" />
            </div>
          </>
        )}

        {/* HIGH-FIDELITY REACT RENDERER (ERA 7.2.3 — REPLACES CellRenderer FOR EDITOR PARITY) */}
        <div className="relative pointer-events-auto">
          <PrimitiveFactory 
            type={item.presentation?.component || 'knob'}
            variant={item.presentation?.variant || 'B_cyan'}
            value={runtimeValue}
            steps={steps}
            manifest={manifest}
            item={item}
            isSelected={isSelected}
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            onValueChange={(val) => onUpdateItem(item.id, { value: val } as any)}
            onClick={handleClick}
            resolveAsset={resolveAsset}
            skin={skin}
          />
        </div>

        {/* SELECTION UI OVERLAY */}
        {isSelected && !isLiveMode && (
          <>
            <div className="absolute -inset-4 border border-primary/20 border-dashed rounded-lg animate-pulse pointer-events-none" />
            <div 
              onPointerDown={(e) => {
                e.stopPropagation();
                dragControls.start(e);
              }}
              className="absolute -top-6 -right-6 p-2 bg-primary/20 border border-primary/40 rounded-xs text-primary hover:bg-primary hover:text-black transition-all cursor-grab active:cursor-grabbing z-[60] shadow-lg backdrop-blur-sm"
            >
              <Move className="w-3.5 h-3.5" />
            </div>
          </>
        )}
      </div>
    </motion.div>
  );
};

export const RackEntity = React.memo(RackEntityBase, (prev, next) => {
  return (
    prev.item.id === next.item.id &&
    JSON.stringify(prev.item.pos) === JSON.stringify(next.item.pos) &&
    prev.item.label === next.item.label &&
    prev.runtimeValue === next.runtimeValue &&
    prev.selectedItemId === next.selectedItemId &&
    prev.isLiveMode === next.isLiveMode &&
    prev.skin === next.skin &&
    prev.zoom === next.zoom &&
    prev.audit.issues.length === next.audit.issues.length &&
    JSON.stringify(prev.manifest.ui?.styles) === JSON.stringify(next.manifest.ui?.styles) &&
    prev.manifest.ui?.skinMode === next.manifest.ui?.skinMode &&
    JSON.stringify(prev.manifest.resources?.assets) === JSON.stringify(next.manifest.resources?.assets) &&
    prev.item.presentation?.asset === next.item.presentation?.asset
  );
});

