        <span className={cn(locale === "en" ? "text-primary" : "text-zinc-600")}>EN</span>
        <span className="text-zinc-800">/</span>
        <span className={cn(locale === "es" ? "text-primary" : "text-zinc-600")}>ES</span>
      </div>
    </button>
  );
}

