            {/* Path Connection Line (Static only) */}
            {!isModular && i < path.nodes.length - 1 && (
              <div className="hidden md:block flex-1 h-px bg-white/5 relative overflow-hidden">
                <motion.div
                  initial={{ x: "-100%" }}
                  animate={{ x: "100%" }}
                  transition={{ repeat: Infinity, duration: 2, ease: "linear" }}
