  manifest: OMEGA_Manifest,
  updateManifest: (updates: Partial<OMEGA_Manifest>) => void,
  addLog: (msg: string) => void
) => {

  const findItem = useCallback((id: string): ManifestEntity | undefined => {
    return [...(manifest.ui?.controls || []), ...(manifest.ui?.jacks || [])].find((i: ManifestEntity) => i.id === id);
  }, [manifest]);

  const updateItem = useCallback((id: string, updates: Partial<ManifestEntity>) => {
    const isJack = manifest.ui?.jacks?.some((j: ManifestEntity) => j.id === id);

    if (isJack) {
      const nextJacks = manifest.ui.jacks.map((j: ManifestEntity) => j.id === id ? { ...j, ...updates } : j);
      updateManifest({ ui: { ...manifest.ui, jacks: nextJacks } });
    } else {
      const nextControls = manifest.ui.controls.map((c: ManifestEntity) => c.id === id ? { ...c, ...updates } : c);
      updateManifest({ ui: { ...manifest.ui, controls: nextControls } });
    }
  }, [manifest, updateManifest]);

  const duplicateItem = useCallback((id: string) => {
    const item = findItem(id);
    if (!item) return;

    const type = manifest.ui?.controls?.some((c: ManifestEntity) => c.id === id) ? 'control' : 'jack';
    const key = type === 'control' ? 'controls' : 'jacks';
    const newItem: ManifestEntity = JSON.parse(JSON.stringify(item));

    const baseId = `${item.id}_copy`;
    let counter = 1;
    let newId = baseId;
    while ([...(manifest.ui?.controls || []), ...(manifest.ui?.jacks || [])].some((i: ManifestEntity) => i.id === newId)) {
      newId = `${baseId}_${counter++}`;
    }

    newItem.id = newId;
    const newList = [...(manifest.ui[key] || []), newItem];
    updateManifest({ ui: { ...manifest.ui, [key]: newList } });
    addLog(`Duplicated ${type}: ${newId}`);
    return newId;
  }, [manifest, findItem, updateManifest, addLog]);

  const removeItem = useCallback((id: string) => {
    const isJack = manifest.ui?.jacks?.some((j: ManifestEntity) => j.id === id);
    if (isJack) {
      const nextJacks = manifest.ui.jacks.filter((j: ManifestEntity) => j.id !== id);
      updateManifest({ ui: { ...manifest.ui, jacks: nextJacks } });
    } else {
      const nextControls = manifest.ui.controls.filter((c: ManifestEntity) => c.id !== id);
      updateManifest({ ui: { ...manifest.ui, controls: nextControls } });
    }
    addLog(`Removed entity: ${id}`);
  }, [manifest, updateManifest, addLog]);

  const addEntity = useCallback((type: 'control' | 'jack', template?: Partial<ManifestEntity>) => {
    const id = `new_${type}_${Date.now().toString().slice(-4)}`;

    // Default base structure
    const baseEntity: ManifestEntity = {
      id,
      type: type === 'control' ? 'knob' : 'port',
      role: type === 'control' ? 'control' : 'stream',
      bind: '',
      label: type === 'control' ? 'New Control' : 'New Jack',
      pos: type === 'control' ? { x: 50, y: 50 } : { x: 50, y: 350 },
      presentation: {
        tab: 'MAIN',
        component: type === 'control' ? 'knob' : 'port',
        variant: 'B_cyan',
        offsetX: 0,
        offsetY: 0,
        attachments: []
      }
    };

    // Merge template if provided (Aseptic Ingestion)
    const newEntity: ManifestEntity = template ? {
      ...baseEntity,
      ...template,
      id, // Preserve generated ID
      pos: baseEntity.pos, // Reset position for placement
      presentation: {
        ...baseEntity.presentation,
        ...(template.presentation || {}),
        tab: 'MAIN' // Force to current plane context
      }
    } as ManifestEntity : baseEntity;

    if (type === 'control') {
      const nextControls = [...(manifest.ui?.controls || []), newEntity];
      updateManifest({ ui: { ...manifest.ui, controls: nextControls } });
    } else {
      const nextJacks = [...(manifest.ui?.jacks || []), newEntity];
      updateManifest({ ui: { ...manifest.ui, jacks: nextJacks } });
    }
    addLog(`Added new ${type}: ${id}`);
    return id;
  }, [manifest, updateManifest, addLog]);

  return {
    findItem,
    updateItem,
    duplicateItem,
    removeItem,
    addEntity
  };
};

'use client';

import { useCallback } from 'react';
import { OMEGA_Manifest, LayoutContainer } from '../../../types/manifest';

export const useLayoutCRUD = (
  manifest: OMEGA_Manifest,
  updateManifest: (updates: Partial<OMEGA_Manifest>) => void,
  addLog: (msg: string) => void
) => {

  const addContainer = useCallback(() => {
    const id = `CONTAINER_${Date.now().toString().slice(-4)}`;
    const newContainer: LayoutContainer = {
      id,
      label: 'New Section',
      pos: { x: 0, y: 0 },
      size: { w: 'full', h: 100 },
      variant: 'default'
    };

    const nextLayout = {
      ...(manifest.ui.layout || { containers: [], gridSnap: 5 }),
      containers: [...(manifest.ui.layout?.containers || []), newContainer]
    };

    updateManifest({ ui: { ...manifest.ui, layout: nextLayout } });
    addLog(`Added new layout container: ${id}`);
    return id;
  }, [manifest, updateManifest, addLog]);

  const updateContainer = useCallback((id: string, updates: Partial<LayoutContainer>) => {
    const nextContainers = manifest.ui.layout?.containers.map(c => c.id === id ? { ...c, ...updates } : c) || [];
    const nextLayout = {
      ...(manifest.ui.layout || { containers: [], gridSnap: 5 }),
      containers: nextContainers
    };
    updateManifest({ ui: { ...manifest.ui, layout: nextLayout } });
  }, [manifest, updateManifest]);

  const removeContainer = useCallback((id: string) => {
    const nextContainers = manifest.ui.layout?.containers.filter(c => c.id !== id) || [];
    const nextLayout = {
      ...(manifest.ui.layout || { containers: [], gridSnap: 5 }),
      containers: nextContainers
    };

    // Also clear references in items
    const nextControls = manifest.ui.controls.map(c => c.presentation?.container === id ? { ...c, presentation: { ...c.presentation, container: undefined } } : c);
    const nextJacks = manifest.ui.jacks.map(j => j.presentation?.container === id ? { ...j, presentation: { ...j.presentation, container: undefined } } : j);

    updateManifest({ ui: { ...manifest.ui, layout: nextLayout, controls: nextControls, jacks: nextJacks } });
    addLog(`Removed container: ${id}`);
  }, [manifest, updateManifest, addLog]);

  return {
    addContainer,
    updateContainer,
    removeContainer
  };
};

'use client';

import { useCallback, Dispatch, SetStateAction } from 'react';
import { OMEGA_Manifest, OMEGA_Modulation } from '../../../types/manifest';

export const useModulationCRUD = (
  setManifest: Dispatch<SetStateAction<OMEGA_Manifest>>
) => {

  const addModulation = useCallback((mod: OMEGA_Modulation) => {
    setManifest((prev: OMEGA_Manifest) => ({
      ...prev,
      modulations: [...(prev.modulations || []), mod]
    }));
  }, [setManifest]);

  const removeModulation = useCallback((id: string) => {
    setManifest((prev: OMEGA_Manifest) => ({
      ...prev,
      modulations: (prev.modulations || []).filter(m => m.id !== id)
    }));
  }, [setManifest]);

  const updateModulation = useCallback((id: string, updates: Partial<OMEGA_Modulation>) => {
    setManifest((prev: OMEGA_Manifest) => ({
      ...prev,
      modulations: (prev.modulations || []).map(m => m.id === id ? { ...m, ...updates } : m)
    }));
  }, [setManifest]);

  return {
    addModulation,
    removeModulation,
    updateModulation
  };
};

'use client';

import { useCallback, Dispatch, SetStateAction } from 'react';
import yaml from 'js-yaml';
import { OMEGA_Manifest } from '../../../types/manifest';
import { ValidationIssue } from '../../../types/validation';
import { purgeUnusedStyles, getUsedResources } from '../../../utils/manifest-editor/governanceUtils';

export const useBundleTransfer = (
  manifest: OMEGA_Manifest,
  setManifest: Dispatch<SetStateAction<OMEGA_Manifest>>,
  wasmBuffer: ArrayBuffer | null,
  extraResources: { name: string, data: ArrayBuffer, type: string }[],
  setExtraResources: Dispatch<SetStateAction<{ name: string, data: ArrayBuffer, type: string }[]>>,
  addLog: (msg: string) => void,
  issues: ValidationIssue[],
  handleWasmUpload: (file: File) => Promise<void>,
  handleContractUpload: (file: File) => Promise<void>,
  handleManifestUpload: (file: File) => Promise<void>
) => {

  const sanitizeSVG = (content: string): string => {
    // Saneamiento básico industrial Era 7.2.3
    return content
      .replace(/<metadata>[\s\S]*?<\/metadata>/gi, '') // Eliminar metadatos de editores
      .replace(/<!--[\s\S]*?-->/g, '')               // Eliminar comentarios
      .replace(/sodipodi:[\w-]+="[^"]*"/g, '')        // Eliminar basura de Inkscape
      .replace(/inkscape:[\w-]+="[^"]*"/g, '');
  };

  const handleResourceUpload = useCallback(async (files: FileList | File[]) => {
    let lastAssetId = '';
    const fileArray = Array.from(files);

    for (const file of fileArray) {
      try {
        let buffer: ArrayBuffer;

        // Industrial Renaming & Path Preservation (Era 7.2.3)
        const isLogo = file.name.toLowerCase().includes('logo') || file.name.toLowerCase().includes('icon');
        // Prefer webkitRelativePath for folder-drop support
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const relativePath = (file as any).webkitRelativePath || file.name;
        const finalName = isLogo && !relativePath.includes('/') ? 'module_logo.svg' : relativePath;
        const assetId = `resources/${finalName}`;
        lastAssetId = assetId;

        if (file.type === 'image/svg+xml' || file.name.endsWith('.svg')) {
          const text = await file.text();
          const sanitized = sanitizeSVG(text);
          buffer = new TextEncoder().encode(sanitized).buffer;
        } else {
          buffer = await file.arrayBuffer();
        }

        addLog(`[SYSTEM] Processing Resource: ${file.name} -> ${finalName}`);

        setExtraResources(prev => [
          ...prev.filter(r => r.name !== finalName),
          { name: finalName, data: buffer, type: file.type }
        ]);

        // Auto-Register in manifest for immediate selector visibility
        setManifest((prev: OMEGA_Manifest) => ({
          ...prev,
          resources: {
            ...prev.resources,
            assets: [
              ...(prev.resources?.assets?.filter((a: { id: string }) => a.id !== assetId) || []),
              { 
                id: assetId, 
                url: assetId, 
                type: (file.type.includes('svg') ? 'svg' : 'image') as 'svg' | 'image' 
              }
            ]
          }
        }));

        addLog(`[OK] Resource '${finalName}' stored and registered in manifest.`);
      } catch (err: unknown) {
        const message = err instanceof Error ? err.message : String(err);
        addLog(`[CRITICAL] Resource Ingestion Failed: ${message}`);
      }
    }
    return lastAssetId;
  }, [addLog, setExtraResources, setManifest]);

  const exportOmegaPack = useCallback(async () => {
    try {
      addLog(`[SYSTEM] Preparing OmegaPack (.zip)...`);

      if (!(window as unknown as { JSZip: unknown }).JSZip) {
        addLog(`[SYSTEM] Loading JSZip dependency...`);
        await new Promise((resolve, reject) => {
          const script = document.createElement('script');
          script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
          script.onload = resolve;
          script.onerror = reject;
          document.head.appendChild(script);
        });
      }

      interface JSZipInstance {
        file: (name: string, data: string | ArrayBuffer | Uint8Array | Blob) => JSZipInstance;
        folder: (name: string) => JSZipInstance;
        generateAsync: (options: { type: 'blob' }) => Promise<Blob>;
      }
      const JSZip = (window as unknown as { JSZip: new () => JSZipInstance }).JSZip;
      const zip = new JSZip();

      const asepticManifest = purgeUnusedStyles(manifest);
      const yamlContent = yaml.dump(asepticManifest, { indent: 2, lineWidth: -1 });
      zip.file(`${manifest.id}.acemm`, yamlContent);

      if (issues.length === 0 || confirm("Audit report will be included. Proceed?")) {
        const contractContent = JSON.stringify(asepticManifest, null, 2);
        zip.file(`${manifest.id}.contract.json`, contractContent);
      }

      const auditReport = `# OMEGA Audit Report\n\nModule ID: ${manifest.id}\nStatus: ${issues.length === 0 ? 'CERTIFIED' : 'DEGRADED'}\nIssues: ${issues.length}\nTimestamp: ${new Date().toISOString()}\n`;
      zip.file(`AUDIT_REPORT.md`, auditReport);

      const { usedAssets } = getUsedResources(asepticManifest);

      if (wasmBuffer) {
        zip.file(`${manifest.id}.wasm`, wasmBuffer);
        addLog(`[SYSTEM] WASM Binary included in pack.`);
      }

      if (extraResources.length > 0) {
        const resFolder = zip.folder("resources");
        let includedCount = 0;

        for (const res of extraResources) {
          const resPath = `resources/${res.name}`;

          // Only include if actually referenced in the manifest
          if (usedAssets.has(resPath) || res.name === 'module_logo.svg') {
            if (res.name === 'module_logo.svg') {
              zip.file(res.name, res.data); // Root for discovery
              addLog(`[SYSTEM] Identity Logo placed in package root.`);
            } else {
              resFolder.file(res.name, res.data);
            }
            includedCount++;
          }
        }
        addLog(`[SYSTEM] Resources: Included ${includedCount} of ${extraResources.length} total assets.`);
      }

      const content = await zip.generateAsync({ type: 'blob' });
      const url = URL.createObjectURL(content);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${manifest.id}.zip`;
      a.click();
      URL.revokeObjectURL(url);

      addLog(`[SUCCESS] OmegaPack exported: ${manifest.id}.zip`);
    } catch (err) {
      addLog(`[ERROR] Failed to generate OmegaPack: ${err}`);
    }
  }, [manifest, issues, wasmBuffer, extraResources, addLog]);

  const handleBulkUpload = useCallback(async (files: FileList | File[]) => {
    const fileList = Array.from(files);
    if (fileList.length === 0) return;

    addLog(`[SYSTEM] Batch Ingestion: Processing ${fileList.length} entities...`);

    const manifests = fileList.filter(f => f.name.endsWith('.acemm'));
    const wasms = fileList.filter(f => f.name.endsWith('.wasm') || f.name.endsWith('.ace'));
    const contracts = fileList.filter(f => f.name.endsWith('.json') && !f.name.endsWith('.acemm'));
    const others = fileList.filter(f => !f.name.endsWith('.acemm') && !f.name.endsWith('.wasm') && !f.name.endsWith('.json'));

    try {
      if (contracts.length > 0) {
        addLog(`[TRACE] Ingesting contract: ${contracts[0].name}`);
        await handleContractUpload(contracts[0]);
      }
      if (wasms.length > 0) {
        addLog(`[TRACE] Ingesting binary: ${wasms[0].name}`);
        await handleWasmUpload(wasms[0]);
      }
      if (manifests.length > 0) {
        addLog(`[TRACE] Ingesting manifest: ${manifests[0].name}`);
        await handleManifestUpload(manifests[0]);
      }

      for (const res of others) {
        addLog(`[TRACE] Ingesting resource: ${res.name}`);
        await handleResourceUpload([res]);
      }

      addLog(`[SUCCESS] Industrial Batch Ingestion finalized.`);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      addLog(`[CRITICAL] Batch Ingestion Aborted: ${message}`);
    }
  }, [handleContractUpload, handleWasmUpload, handleManifestUpload, handleResourceUpload, addLog]);

  const handleRemoveResource = useCallback((name: string) => {
    setExtraResources(prev => prev.filter(r => r.name !== name));
    addLog(`[SYSTEM] Resource removed: ${name}`);
  }, [setExtraResources, addLog]);

  return {
    exportOmegaPack,
    handleBulkUpload,
    handleResourceUpload,
    handleRemoveResource
  };
};

'use client';

import { useCallback, Dispatch, SetStateAction } from 'react';
import yaml from 'js-yaml';
import { OMEGA_Manifest, ManifestEntity, ComponentType, AttachmentType, Attachment } from '../../../types/manifest';
import { ValidationIssue } from '../../../types/validation';
import { purgeUnusedStyles } from '../../../utils/manifest-editor/governanceUtils';

export const useManifestTransfer = (
  manifest: OMEGA_Manifest,
  setManifest: Dispatch<SetStateAction<OMEGA_Manifest>>,
  addLog: (msg: string) => void,
  issues: ValidationIssue[]
) => {

  const handleManifestUpload = useCallback(async (file: File) => {
    addLog(`Ingesting Manifest: ${file.name}...`);
    try {
      const content = await file.text();
      const parsed = yaml.load(content) as Partial<OMEGA_Manifest> & { name?: string };

      if (!parsed || typeof parsed !== 'object') throw new Error("Invalid manifest format.");

      if (!parsed.ui) parsed.ui = { dimensions: { width: 120, height: 420 }, controls: [], jacks: [] };
      if (!parsed.metadata) parsed.metadata = { name: parsed.name || "Unnamed Module", family: "utility" };

      const getNum = (v: unknown) => {
        const n = parseFloat(String(v));
        return isNaN(n) ? 0 : n;
      };

      const normalize = (list: unknown[], defaultTab: string): ManifestEntity[] => (list || []).map((cRaw: unknown, idx) => {
        const c = cRaw as { 
          id?: string; 
          type?: string; 
          role?: string; 
          bind?: string; 
          label?: string; 
          pos?: { x?: number; y?: number };
          presentation?: {
            tab?: string;
            variant?: string;
            component?: string;
            offsetX?: number;
            offsetY?: number;
            container?: string;
            group?: string;
            attachments?: unknown[];
            precision?: number;
            ui_precision?: number;
          };
        };
        const rawPos = c.pos || {};
        const x = getNum(rawPos.x);
        const y = getNum(rawPos.y);
        const defaultRole = defaultTab === 'PATCHING' ? 'stream' : 'control';

        return {
          id: String(c.id || `entity_${defaultTab}_${idx}`),
          type: String(c.type || (defaultTab === 'PATCHING' ? 'port' : 'knob')).toLowerCase(),
          role: String(c.role || defaultRole),
          bind: String(c.bind || ''),
          label: c.label,
          pos: { x, y },
          presentation: {
            tab: String(c.presentation?.tab || (defaultTab === 'PATCHING' ? 'MAIN' : defaultTab)),
            variant: String(c.presentation?.variant || 'B_cyan'),
            component: String(c.presentation?.component || c.type || (defaultTab === 'PATCHING' ? 'port' : 'knob')).toLowerCase() as ComponentType,
            offsetX: getNum(c.presentation?.offsetX),
            offsetY: getNum(c.presentation?.offsetY),
            container: c.presentation?.container || c.presentation?.group,
            group: c.presentation?.group,
            attachments: (c.presentation?.attachments || []).map((attRaw: unknown) => {
              const att = attRaw as { 
                type?: string; 
                position?: string; 
                offsetX?: unknown; 
                offsetY?: unknown; 
                variant?: string; 
                text?: string; 
              };
              return {
                id: `att_${idx}_${Math.random().toString(36).substr(2, 4)}`,
                type: String(att.type || 'label') as AttachmentType,
                position: String(att.position || 'bottom') as Attachment['position'],
                offsetX: getNum(att.offsetX),
                offsetY: getNum(att.offsetY),
                variant: String(att.variant || 'B_cyan'),
                text: att.text
              };
            }),
            precision: getNum(c.presentation?.precision) || 6,
            ui_precision: getNum(c.presentation?.ui_precision) || 2,
          }
        };
      });

      const finalManifest: OMEGA_Manifest = {
        schemaVersion: String(parsed.schemaVersion || '7.1'),
        id: String(parsed.id || 'unknown_module'),
        metadata: {
          name: String(parsed.metadata?.name || parsed.name),
          family: String(parsed.metadata?.family || 'utility').toLowerCase(),
          author: parsed.metadata?.author,
          tags: parsed.metadata?.tags || [],
          rack: parsed.metadata?.rack
        },
        ui: {
          dimensions: { 
            width: getNum(parsed.ui.dimensions?.width) || 120, 
            height: getNum(parsed.ui.dimensions?.height) || 420 
          },
          controls: normalize(parsed.ui.controls, 'MAIN'),
          jacks: normalize(parsed.ui.jacks, 'MAIN'),
          skin: parsed.ui.skin || 'industrial',
          layout: parsed.ui.layout || { containers: [], gridSnap: 5 }
        },
        resources: {
          wasm: String(parsed.resources?.wasm || 'module.wasm'),
          contract: parsed.resources?.contract
        },
        modulations: parsed.modulations || []
      };

      setManifest(finalManifest);
      addLog(`Success: UI state reconstructed for '${finalManifest.metadata.name}'.`);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      addLog(`[CRITICAL] Ingestion Failure: ${message}`);
    }
  }, [addLog, setManifest]);

  const exportManifest = useCallback(() => {
    if (issues.length > 0) {
      if (!confirm(`Manifest has ${issues.length} issues. Export anyway?`)) return;
    }

    const asepticManifest = purgeUnusedStyles(manifest);
    const yamlContent = yaml.dump(asepticManifest, { 
      indent: 2, 
      lineWidth: -1,
      schema: yaml.JSON_SCHEMA 
    });
    const blob = new Blob([yamlContent], { type: 'text/yaml' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${manifest.id}.acemm`;
    a.click();
    URL.revokeObjectURL(url);
    addLog(`[OK] Exported manifest: ${manifest.id}.acemm`);
  }, [manifest, issues, addLog]);

  const exportCADBlueprint = useCallback(async () => {
    const { CADExportService } = await import('../../../services/cadExportService');
    const svg = CADExportService.generateSVGBlueprint(manifest, {
      skin: manifest.ui.skin || 'industrial',
      drillLayer: false,
      silkscreenLayer: true,
      dimensions: true
    });
    const blob = new Blob([svg], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `CAD_BLUEPRINT_${manifest.id}.svg`;
    a.click();
    URL.revokeObjectURL(url);
    addLog(`[OK] Exported Industrial CAD Blueprint: ${manifest.id}.svg`);
  }, [manifest, addLog]);

  return {
    handleManifestUpload,
    exportManifest,
    exportCADBlueprint
  };
};

'use client';

import { useCallback, Dispatch, SetStateAction } from 'react';
import { OMEGA_Manifest } from '../../../types/manifest';
import { WasmLoaderService, OmegaContract } from '../../../services/wasmLoader';
import { wasmRuntime } from '../../../services/wasmRuntime';
import { ContractService } from '../../../services/contractService';

export const useWasmTransfer = (
  manifest: OMEGA_Manifest,
  setManifest: Dispatch<SetStateAction<OMEGA_Manifest>>,
  setContract: Dispatch<SetStateAction<OmegaContract | null>>,
  setWasmBuffer: Dispatch<SetStateAction<ArrayBuffer | null>>,
  addLog: (msg: string) => void
) => {

  const exportContract = useCallback((format: 'ts' | 'cpp') => {
    addLog(`[SYSTEM] Exporting Technical Contract (${format.toUpperCase()})...`);
    const content = format === 'ts' 
      ? ContractService.generateTypeScriptContract(manifest)
      : ContractService.generateCppContract(manifest);

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = format === 'ts' ? 'schema_ids.ts' : 'OmegaRegistry.h';
    a.click();
    URL.revokeObjectURL(url);
    addLog(`[OK] Contract exported as ${a.download}`);
  }, [manifest, addLog]);

  const syncManifestWithContract = useCallback((newContract: OmegaContract, filename: string) => {
    setManifest((prev: OMEGA_Manifest) => ({
      ...prev,
      id: newContract.id || prev.id,
      metadata: {
        ...(prev.metadata || {}),
        name: (prev.metadata?.name === 'New Module' || !prev.metadata?.name) ? (newContract.name || newContract.id) : prev.metadata.name,
        family: newContract.family || prev.metadata?.family || 'oscillator'
      },
      resources: {
        ...(prev.resources || {}),
        wasm: filename,
        contract: filename.replace('.wasm', '.contract.json')
      }
    }));
  }, [setManifest]);

  const handleWasmUpload = useCallback(async (file: File) => {
    addLog(`Loading WASM Binary: ${file.name}...`);
    try {
      const buffer = await file.arrayBuffer();
      setWasmBuffer(buffer);
      const extractedContract = await WasmLoaderService.extractContract(file);

      // Industrial Fingerprinting: Generate hash from the contract to bind it with the manifest
      const { IntegrityService } = await import('../../../services/integrityService');
      extractedContract.firmwareHash = await IntegrityService.generateHash(extractedContract as unknown as Record<string, unknown>);

      setContract(extractedContract);
      addLog(`[OK] Contract extracted and fingerprinted: ${extractedContract.firmwareHash.slice(0, 8)}`);

      const success = await wasmRuntime.loadWasm(buffer);
      if (success) {
        addLog(`[OK] Simulation engine synchronized with binary logic.`);
      }

      syncManifestWithContract(extractedContract, file.name);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      addLog(`[CRITICAL] WASM Load Failed: ${message}`);
    }
  }, [addLog, setContract, setWasmBuffer, syncManifestWithContract]);

  const handleContractUpload = useCallback(async (file: File) => {
    addLog(`Ingesting Technical Contract: ${file.name}...`);
    try {
      const content = await file.text();
      const rawData = JSON.parse(content);
      const data = rawData.contract || rawData;

      if (!data.id || !data.ports) {
        throw new Error("Missing mandatory 'id' or 'ports' fields in contract.");
      }

      const loadedContract: OmegaContract = {
        omega_version: data.omega_version || data.version || "7.0",
        id: String(data.id),
        name: data.name || data.id,
        family: (data.family || "utility").toLowerCase(),
        parameters: data.parameters || [],
        ports: data.ports || []
      };

      interface RawParam { id?: string; name?: string; min?: number; max?: number; default?: number; }
      interface RawPort { id?: string; name?: string; type?: string; direction?: string; }

      loadedContract.parameters = (loadedContract.parameters || []).map((p: RawParam) => ({ 
        min: 0, max: 1, default: 0, 
        ...p, 
        id: String(p.id || p.name).toLowerCase(),
        name: String(p.name || p.id)
      } as OmegaContract['parameters'][0]));

      loadedContract.ports = (loadedContract.ports || []).map((p: RawPort) => ({ 
        type: 'audio', direction: 'input', 
        ...p, 
        id: String(p.id || p.name).toLowerCase() 
      } as OmegaContract['ports'][0]));

      const { IntegrityService } = await import('../../../services/integrityService');
      loadedContract.firmwareHash = await IntegrityService.generateHash(loadedContract as unknown as Record<string, unknown>);

      setContract(loadedContract);
      addLog(`[AUDIT] Contract '${loadedContract.id}' validated and fingerprinted.`);
      syncManifestWithContract(loadedContract, 'module.wasm');
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      addLog(`[CRITICAL] Contract Load Failed: ${message}`);
    }
  }, [addLog, setContract, syncManifestWithContract]);

  return {
    handleWasmUpload,
    handleContractUpload,
    exportContract
  };
};

