import { useEffect, useMemo } from 'react';

interface AssetResource {
  name: string;
  data: ArrayBuffer;
  type: string;
}

/**
 * useAssetManager (Fase 13)
 * Manages local blob URLs for resources in the workspace.
 * Automatically detects images/SVGs and creates accessible URLs.
 */
export function useAssetManager(extraResources: AssetResource[]) {
  const assetUrls = useMemo(() => {
    const urls: Record<string, string> = {};

    extraResources.forEach(res => {
      if (res.type.startsWith('image/') || res.name.endsWith('.svg') || res.name.endsWith('.png') || res.name.endsWith('.jpg')) {
        const blob = new Blob([res.data], { type: res.type || 'image/png' });
        // Standard OMEGA Prefix
        urls[`resources/${res.name}`] = URL.createObjectURL(blob);
      }
    });

    return urls;
  }, [extraResources]);

  useEffect(() => {
    return () => {
      Object.values(assetUrls).forEach(url => URL.revokeObjectURL(url));
    };
  }, [assetUrls]);

  /**
   * Resolves an asset ID or URL to a real browser URL.
   * Supports:
   * - asset://filename.png -> mapped blob URL
   * - filename.png -> mapped blob URL (fallback)
   * - data:... -> self
   * - http... -> self
   */
  const resolveAsset = (assetRef: string | undefined): string | undefined => {
    if (!assetRef) return undefined;

    if (assetRef.startsWith('data:') || assetRef.startsWith('http')) {
      return assetRef;
    }

    const cleanId = assetRef.replace('asset://', '');
    return assetUrls[cleanId] || assetUrls[assetRef];
  };

  return {
    assetUrls,
    resolveAsset
  };
}

import { useState, useEffect, useMemo, useCallback } from 'react';
import { OMEGA_Manifest, LibraryAsset } from '@/types/manifest';

/**
 * useAssetRegistry (Era 7.2.3)
 * Centralizes the retrieval and filtering of industrial assets (Manifest & Libraries).
 */
export function useAssetRegistry(manifest: OMEGA_Manifest, mode: 'statics' | 'sequences' = 'statics') {
  const [library, setLibrary] = useState<LibraryAsset[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const assets = useMemo(() => manifest.resources?.assets || [], [manifest.resources?.assets]);

  useEffect(() => {
    const loadLibrary = async () => {
      try {
        setIsLoading(true);
        const registryPath = mode === 'sequences' 
          ? '/assets/elements/sequences/sequences-registry.json'
          : '/assets/elements/statics/statics-registry.json';

        const res = await fetch(registryPath);
        const data = await res.json();
        setLibrary(data[mode] || []);
      } catch (err) {
        console.error(`Error loading ${mode} library:`, err);
      } finally {
        setIsLoading(false);
      }
    };

    loadLibrary();
  }, [mode]);

  const resolveAsset = useCallback((id: string | undefined) => {
    if (!id) return undefined;
    const asset = assets.find(a => a.id === id);
    return asset?.url || id;
  }, [assets]);

  const getSequences = () => assets.filter(a => (a.frames && a.frames > 1) || a.id.includes('sequences'));
  const getStatics = () => assets.filter(a => !(a.frames && a.frames > 1) && !a.id.includes('sequences'));

  return {
    assets,
    library,
    isLoading,
    resolveAsset,
    getSequences,
    getStatics
  };
}

