import { ColorResolver } from '../utils/ColorResolver';

export interface AttachmentProps {
    type: 'label' | 'led' | 'graphic' | 'graphic-fragment' | 'knob' | 'port' | 'slider-v' | 'slider-h' | 'switch' | 'push' | 'stepper' | 'path' | 'display';
    variant?: string;
    text?: string;
    value?: number;
    steps?: number;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    style?: any;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    manifest?: any;
    resolveAsset?: (id: string | undefined) => string | undefined;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    inherited?: any;
}

export const AttachmentRenderer = {
    renderAttachmentHTML(props: AttachmentProps): string {
        const { type } = props;

        switch (type) {
            case 'label':
                return this.renderLabelHTML(props);
            case 'led':
                return this.renderLedHTML(props);
            case 'graphic':
            case 'graphic-fragment':
                return this.renderGraphicHTML(props);
            default:
                return '';
        }
    },

    renderLabelHTML(props: AttachmentProps): string {
        const { text, style, manifest } = props;
        const color = ColorResolver.resolve(style?.color || style?.fontColor || '#ffffff', manifest);
        const fontSize = style?.fontSize || 8;
        const font = style?.font || 'Inter';
        const weight = style?.fontWeight || '900';

        return `
          <div class="attachment-label" style="
            color: ${color}; 
            font-size: ${fontSize}px; 
            font-family: ${font}; 
            font-weight: ${weight};
            text-transform: uppercase;
            letter-spacing: 0.1em;
            pointer-events: none;
            white-space: nowrap;
          ">
            ${text || 'LABEL'}
          </div>
        `;
    },

    renderLedHTML(props: AttachmentProps): string {
        const { value = 0, style, manifest } = props;
        const color = ColorResolver.resolve(style?.color || '#00f2ff', manifest);
        const isActive = value > 0.5;
        const size = style?.size || 6;

        const glow = isActive ? `box-shadow: 0 0 ${size}px ${color};` : '';
        const opacity = isActive ? 1 : 0.2;

        return `
          <div class="attachment-led" style="
            width: ${size}px; 
            height: ${size}px; 
            background-color: ${color}; 
            border-radius: 50%;
            opacity: ${opacity};
            ${glow}
            transition: all 0.2s ease;
          "></div>
        `;
    },

    renderGraphicHTML(props: AttachmentProps): string {
        const { style, resolveAsset } = props;

        const assetId = style?.asset;
        let assetUrl = resolveAsset ? resolveAsset(assetId) : assetId;

        // Final fallback for previewing
        if (assetId && !assetUrl && !assetId.startsWith('http') && !assetId.startsWith('/')) {
            assetUrl = `/assets/elements/cells/knobs/${assetId}.png`;
        }

        const finalOpacity = style?.opacity !== undefined ? style.opacity : 1;
        const fitting = style?.fitting || 'contain';
        const width = style?.width || 48;
        const height = style?.height || 48;

        // Clean image style - NO ROTATION, NO FILMSTRIP
        const imageStyle = assetUrl ? `background-image: url('${assetUrl}'); background-size: ${fitting};` : 'background-color: rgba(255,0,255,0.2); border: 1px dashed magenta;';

        return `
          <div class="attachment-graphic" style="
            position: absolute; 
            left: 50%; 
            top: 50%; 
            transform: translate(-50%, -50%); 
            width: ${width}px; 
            height: ${height}px;
            background-repeat: no-repeat; 
            background-position: center; 
            opacity: ${finalOpacity};
            ${imageStyle}
          ">
          </div>
        `;
    }
};

/**
 * ⚠️ OMEGA UI CORE — MASTER ENGINE (Era 7.2.3)
 * ---------------------------------------------------------------------------
 * This is the SINGLE SOURCE OF TRUTH for OMEGA rendering.
 * It handles both architectural structures and primitive controls.
 * ---------------------------------------------------------------------------
 */

import { renderKnobHTML } from './KnobRenderer';
import { renderPortHTML } from './PortRenderer';
import { renderLedHTML } from './LedRenderer';
import { renderSliderHTML } from './SliderRenderer';
import { renderDisplayHTML } from './DisplayRenderer';
import { renderSwitchHTML } from './SwitchRenderer';
import { renderStepperHTML } from './StepperRenderer';
import { renderSelectHTML } from './SelectRenderer';
import { renderScopeHTML } from './ScopeRenderer';
import { renderTerminalHTML } from './TerminalRenderer';
import { renderIllustrationHTML } from './IllustrationRenderer';
import { renderSequenceHTML } from './SequenceRenderer';
import { AttachmentRenderer } from './AttachmentRenderer';

import { parseVariant } from './utils/VariantParser';
import { getComponentRadius } from './utils/CellMetrics';
import { renderAttachmentStackHTML } from './utils/AttachmentStack';
import { getInheritedTypography } from './utils/TypographyInheritance';
import { ColorResolver } from '../utils/ColorResolver';

export interface CellOptions {
  skin: string;
  zoom: number;
  runtimeValue: number;
  steps: number;
  isSelected?: boolean;
  isLiveMode?: boolean;
  isError?: boolean;
  resolveAsset?: (ref: string | undefined) => string | undefined;
  manifest?: OMEGA_Manifest;
  activeTab?: string;
}

import type { ManifestEntity, OMEGA_Manifest, OmegaStyleNode, OMEGA_Asset } from '../types/manifest';

interface RendererExtraOptions {
  assetUrl?: string;
  assetDef?: OMEGA_Asset;
  steps: number;
  runtimeValue: number;
  inherited: Record<string, unknown>;
  manifest?: OMEGA_Manifest;
  resolveAsset?: (id: string | undefined) => string | undefined;
}

/**
 * Registry of primitive renderers for industrial dispatching.
 */
const COMP_RENDERER_MAP: Record<string, (item: ManifestEntity, props: Record<string, unknown>, options: RendererExtraOptions) => string> = {
  'sequence-layer': (item, props, opt) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const style = (item.presentation?.style as any) || {};
    return renderSequenceHTML({
      assetUrl: opt.assetUrl,
      value: opt.runtimeValue,
      frames: style.frames || 1,
      frameWidth: style.frameWidth || 48,
      frameHeight: style.frameHeight || 48,
      orientation: style.orientation || 'v',
      opacity: style.opacity !== undefined ? style.opacity : 1,
      style
    });
  },
  'graphic-fragment': (item, props, opt) => {
    return AttachmentRenderer.renderAttachmentHTML({
      type: 'graphic-fragment',
      variant: item.presentation?.variant || 'A_default',
      text: item.label || '',
      value: opt.runtimeValue,
      steps: opt.steps,
      style: item.presentation?.style,
      manifest: opt.manifest,
      resolveAsset: opt.resolveAsset
    });
  },
  'knob': (item, props, opt) => {
    const isCustom = opt.manifest?.ui?.skinMode === 'custom';
    const style = item.presentation?.style || {};

    // Explicitly resolve both channels separately
    const resolvedIndicator = isCustom ? ColorResolver.resolve(style.indicatorColor, opt.manifest) : undefined;
    const resolvedMain = isCustom ? ColorResolver.resolve(style.color || item.presentation?.color, opt.manifest) : undefined;

    return renderKnobHTML({ 
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ...(props as any), 
      assetUrl: opt.assetUrl, 
      frames: opt.assetDef?.frames, 
      orientation: opt.assetDef?.orientation,
      // NO FALLBACK to main color here. If resolvedIndicator is transparent, the marker should be transparent.
      explicitMarkerColor: resolvedIndicator, 
      style: { ...style, color: resolvedMain, indicatorColor: resolvedIndicator },
      inheritedFont: isCustom ? (style.font || item.presentation?.font || opt.inherited.font) : opt.inherited.font,
      inheritedColor: opt.inherited.color,
      inheritedSize: opt.inherited.size
    });
  },
  'port': (item, props, opt) => {
    const isCustom = opt.manifest?.ui?.skinMode === 'custom';
    return renderPortHTML({ 
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ...(props as any), 
      label: item.label || '', 
      explicitColor: item.presentation?.variant,
      customSignalColor: isCustom ? ColorResolver.resolve(item.presentation?.style?.color || item.presentation?.color, opt.manifest) : undefined,
      style: item.presentation?.style,
      inheritedFont: isCustom ? (item.presentation?.style?.font || item.presentation?.font || opt.inherited.font) : opt.inherited.font,
      inheritedColor: opt.inherited.color,
      inheritedSize: opt.inherited.size
    });
  },
  'led': (item, props, opt) => {
    const isCustom = opt.manifest?.ui?.skinMode === 'custom';
    return renderLedHTML({ 
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ...(props as any),
      explicitColor: isCustom ? ColorResolver.resolve(item.presentation?.style?.color || item.presentation?.color, opt.manifest) : undefined
    });
  },
  'display': (item, props, opt) => {
    const variant = item.presentation?.variant || '';
    const mode = variant.includes('lcd') ? 'lcd' : (variant.includes('led') ? 'led' : 'oled');
    const isCustom = opt.manifest?.ui?.skinMode === 'custom';
    return renderDisplayHTML({ 
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ...(props as any), 
      mode, 
      steps: opt.steps,
      explicitTextColor: isCustom ? ColorResolver.resolve(item.presentation?.style?.color || item.presentation?.color, opt.manifest as OMEGA_Manifest) : undefined,
      explicitGlassColor: isCustom ? ColorResolver.resolve(item.presentation?.style?.glassColor || (item.presentation as unknown as Record<string, unknown>)?.glassColor as string, opt.manifest as OMEGA_Manifest) : undefined,
      inheritedFont: isCustom ? (item.presentation?.style?.font || item.presentation?.font || opt.inherited.font) : opt.inherited.font,
      inheritedColor: opt.inherited.color,
      inheritedSize: opt.inherited.size
    });
  },
  'slider-v': (item, props, opt) => renderSliderHTML({ 
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ...(props as any), 
    type: 'slider-v', 
    ...opt.inherited,
    assetUrl: opt.assetUrl,
    frames: opt.assetDef?.frames,
    orientation: opt.assetDef?.orientation
  }),
  'slider-h': (item, props, opt) => renderSliderHTML({ 
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ...(props as any), 
    type: 'slider-h', 
    ...opt.inherited,
    assetUrl: opt.assetUrl,
    frames: opt.assetDef?.frames,
    orientation: opt.assetDef?.orientation
  }),
  'switch': (item, props, opt) => renderSwitchHTML({ 
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ...(props as any), 
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ...(opt.inherited as any)
  }),
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  'button': (item, props, opt) => renderStepperHTML({ ...(props as any), type: 'button', text: item.label || '', ...(opt.inherited as any) }),
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  'push': (item, props, opt) => renderStepperHTML({ ...(props as any), type: 'push', text: item.label || '', ...(opt.inherited as any) }),
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  'stepper': (item, props, opt) => renderStepperHTML({ ...(props as any), type: 'stepper', text: item.label || '', ...(opt.inherited as any) }),
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  'select': (item, props, opt) => renderSelectHTML({ ...(props as any), options: item.presentation?.options || [], ...(opt.inherited as any) }),
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  'scope': (item, props, opt) => renderScopeHTML({ ...(props as any), ...(opt.inherited as any) }),
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  'terminal': (item, props, opt) => renderTerminalHTML({ ...(props as any), ...(opt.inherited as any) }),
  'illustration': (item, props, opt) => renderIllustrationHTML({ assetUrl: opt.assetUrl, size: item.presentation?.size || { w: 40, h: 40 }, variant: item.presentation?.variant || 'contain', id: item.id }),
  'label': (item, props, opt) => AttachmentRenderer.renderAttachmentHTML({
    type: 'label',
    variant: item.presentation?.variant || 'default',
    text: item.label || '',
    style: props.style,
    manifest: opt.manifest,
    inherited: opt.inherited
  })
};

export class CellRenderer {
  /**
   * RACK CHASSIS RENDERER (Internal)
   * Handles the main module frame and canonical screw positioning.
   */
  private static renderRackHTML(entity: ManifestEntity, options: CellOptions): string {
    const { manifest, resolveAsset, activeTab = 'MAIN' } = options;
    const presentation = entity.presentation || {};
    const variant = presentation.variant || 'default';

    // Resolve the style for this specific tab if mapping exists
    const tabStyleId = manifest?.ui?.layout?.tabStyles?.[activeTab];
    const targetStyleId = tabStyleId || variant;

    const rackStyles = manifest?.ui?.styles?.rack || [];
    const libStyle = rackStyles.find((s) => s.id === targetStyleId) || { aesthetics: {} as Partial<OmegaStyleNode> };
    const genetics = libStyle.aesthetics || {};
    const aesthetics = presentation.style || {};

    const bgColor = ColorResolver.resolve(aesthetics.color || genetics.color || 'chassis', manifest);

    // Resolve bgAsset with Tab-Awareness
    const faceplateConfig = manifest?.ui?.faceplate;
    let bgAsset = aesthetics.asset || genetics.asset;

    if (!bgAsset && faceplateConfig) {
      if (typeof faceplateConfig === 'string') {
        bgAsset = faceplateConfig;
      } else {
        bgAsset = (faceplateConfig as Record<string, string>)[activeTab] || (faceplateConfig as Record<string, string>)['MAIN'];
      }
    }

    const resolveBackgroundCSS = (assetId: string | undefined, fitting: string = 'stretch') => {
      const url = resolveAsset ? resolveAsset(assetId) : undefined;
      if (!url) return '';

      let size = '100% 100%';
      let repeat = 'no-repeat';
      const position = 'center';

      switch(fitting) {
        case 'cover':   size = 'cover'; break;
        case 'contain': size = 'contain'; break;
        case 'tile':    size = 'auto'; repeat = 'repeat'; break;
        case 'center':  size = 'auto'; break;
      }

      return `background-image: url('${url}') !important; background-size: ${size} !important; background-repeat: ${repeat} !important; background-position: ${position} !important;`;
    };

    const faceplateMode = manifest?.ui?.faceplateMode || 'stretch';
    const bgStyles = resolveBackgroundCSS(bgAsset, faceplateMode);

    const rounding = aesthetics.rounding ?? genetics.rounding ?? 0;
    const borderWidth = aesthetics.borderWidth ?? genetics.borderWidth ?? 0;

    //    const screwStyles = manifest?.ui?.styles?.['mounting-screw'] || [];
    const screwFragment = presentation.attachments?.find((a) => a.type === 'knob' && a.variant === 'rack-screw');

    const sAesthetics = (screwFragment?.style || {}) as OmegaStyleNode;
    const screwStyles = manifest?.ui?.styles?.['rack-screw'] || [];
    const sGenetics = screwStyles.find((s) => s.id === (screwFragment?.variant || 'default'))?.aesthetics || {};

    const screwSpacing = sAesthetics.spacing ?? sGenetics.spacing ?? 8;
    const screwCount = manifest?.ui?.hardware?.screwCount ?? 4;
    const screwMapping = manifest?.ui?.hardware?.screwMapping || [];
    const masterScrewOffset = manifest?.ui?.hardware?.screwOffset;
    const finalScrewSpacing = masterScrewOffset !== undefined ? masterScrewOffset : screwSpacing;

    // Define standard positions based on count
    const positions: { top: boolean; left: boolean; xPercent?: number; yPercent?: number }[] = [];
    if (screwCount >= 4) {
      positions.push({ top: true, left: true });
      positions.push({ top: true, left: false });
      positions.push({ top: false, left: true });
      positions.push({ top: false, left: false });
    }
    if (screwCount === 6) {
      positions.push({ top: true, left: false, xPercent: 50 }); // Top Mid
      positions.push({ top: false, left: false, xPercent: 50 }); // Bottom Mid
    } else if (screwCount === 8) {
      positions.push({ top: true, left: false, xPercent: 33 }); // Top Mid L
      positions.push({ top: true, left: false, xPercent: 66 }); // Top Mid R
      positions.push({ top: false, left: false, xPercent: 33 }); // Bottom Mid L
      positions.push({ top: false, left: false, xPercent: 66 }); // Bottom Mid R
    }

    const renderScrew = (pos: typeof positions[0], idx: number) => {
      // Resolve style for this specific position
      const posStyleId = screwMapping[idx];
      const posLibStyle = manifest?.ui?.styles?.['mounting-screw']?.find((s) => s.id === posStyleId);
      const posAesthetics = posLibStyle?.aesthetics || {};

      const sColor = ColorResolver.resolve(posAesthetics.color || sAesthetics.color || sGenetics.color || 'hardware', manifest);
      const sAssetId = posAesthetics.asset || sAesthetics.asset || sGenetics.asset;
      const sFitting = posAesthetics.fitting || sAesthetics.fitting || sGenetics.fitting || 'cover';
      const sAssetCSS = resolveBackgroundCSS(sAssetId, sFitting);

      const stylePos = `
        position: absolute;
        ${pos.top ? 'top' : 'bottom'}: ${finalScrewSpacing}px;
        ${pos.xPercent ? `left: ${pos.xPercent}%; transform: translateX(-50%);` : (pos.left ? 'left' : 'right') + `: ${finalScrewSpacing}px;`}
      `;

      return `
        <div style="
          ${stylePos}
          width: 14px;
          height: 14px;
          background-color: ${sAssetCSS ? 'transparent' : sColor};
          ${sAssetCSS || `
            background-image: 
              radial-gradient(circle at 30% 30%, rgba(255,255,255,0.2) 0%, transparent 40%),
              radial-gradient(circle at center, rgba(0,0,0,0.4) 0%, rgba(0,0,0,0.1) 20%, transparent 60%),
              linear-gradient(135deg, rgba(255,255,255,0.15) 0%, transparent 50%, rgba(0,0,0,0.2) 100%) !important;
            background-size: cover !important;
          `}
          border-radius: 50%;
          box-shadow: 0 2px 5px rgba(0,0,0,0.5), inset 0 1px 1px rgba(255,255,255,0.1);
          display: flex;
          align-items: center;
          justify-content: center;
        ">
          ${sAssetCSS ? '' : `
            <div style="
              width: 8px;
              height: 2px;
              background-color: rgba(0,0,0,0.4);
              transform: rotate(45deg);
              border-radius: 1px;
            "></div>
          `}
        </div>
      `;
    };

    return `
      <div class="industrial-rack-chassis"
        style="position: absolute; inset: 0; background-color: ${bgColor}; ${bgStyles} border-radius: ${rounding}px; border: ${borderWidth}px solid rgba(255,255,255,0.05); overflow: hidden;">
        ${screwFragment ? positions.map((p, i) => renderScrew(p, i)).join('') : ''}
      </div>
    `.trim();
  }

  /**
   * ARCHITECTURAL RENDERER (Internal)
   * Handles Containers, Groups and Plates.
   */
  private static renderContainerHTML(entity: ManifestEntity, options: CellOptions): string {
    const { manifest, resolveAsset, isSelected, isError } = options;
    const presentation = entity.presentation || {};
    const aesthetics = presentation.style || {};
    const variant = presentation.variant || 'default';

    const libStyles = manifest?.ui?.styles?.container || [];
    const libStyle = libStyles.find((s) => s.id === variant) || { aesthetics: {} as Partial<OmegaStyleNode> };
    const genetics = libStyle.aesthetics || {};

    const label = entity.label || 'LABEL';

    // Resolved Chromatics
    const bgColor = ColorResolver.resolve(aesthetics.color || genetics.color, manifest);
    const borderColor = ColorResolver.resolve(aesthetics.indicatorColor || genetics.indicatorColor, manifest);
    const labelBg = ColorResolver.resolve(aesthetics.labelBg || genetics.labelBg, manifest);
    const fontColor = ColorResolver.resolve(aesthetics.fontColor || genetics.fontColor || '#ffffff', manifest);

    // Mechanical Properties
    const bgAsset = aesthetics.asset || genetics.asset;
    const bgUrl = resolveAsset ? resolveAsset(bgAsset) : undefined;
    const rounding = aesthetics.rounding ?? genetics.rounding ?? 0;
    const borderWidth = aesthetics.borderWidth ?? genetics.borderWidth ?? 0;
    const opacity = aesthetics.opacity ?? genetics.opacity ?? 1.0;

    // Spatial & Typographic Fragments
    const labelX = aesthetics.labelX ?? genetics.labelX ?? 0;
    const labelY = aesthetics.labelY ?? genetics.labelY ?? 0;
    const labelW = aesthetics.labelW ?? genetics.labelW ?? 0;
    const labelH = aesthetics.labelH ?? genetics.labelH ?? 0;
    const labelRounding = aesthetics.labelRounding ?? genetics.labelRounding ?? 0;
    const labelPadding = aesthetics.labelPadding ?? genetics.labelPadding ?? 4;
    const font = aesthetics.font || genetics.font || 'Inter';
    const fontSize = aesthetics.fontSize || genetics.fontSize || 10;
    const alignment = aesthetics.alignment || genetics.alignment || 'left';
    const flexAlign = alignment === 'left' ? 'flex-start' : (alignment === 'right' ? 'flex-end' : 'center');
    const spacing = aesthetics.spacing || genetics.spacing || 0;

    return `
      <div class="industrial-container-surface ${isSelected ? 'selected' : ''} ${isError ? 'error' : ''}"
        style="position: absolute; inset: 0; background-color: ${bgColor}; background-image: ${bgUrl ? `url(${bgUrl})` : 'none'}; background-size: cover; background-position: center; border: ${borderWidth}px solid ${borderColor}; border-radius: ${rounding}px; opacity: ${opacity}; overflow: hidden;">
        <div class="container-label-fragment"
          style="position: absolute; left: ${labelX}px; top: ${labelY}px; width: ${labelW ? `${labelW}px` : 'auto'}; height: ${labelH ? `${labelH}px` : 'auto'}; background-color: ${labelBg}; border-radius: ${labelRounding}px; display: flex; align-items: center; justify-content: ${flexAlign}; padding: ${labelPadding}px; white-space: nowrap; z-index: 10;">
          <span style="font-family: ${font}; font-size: ${fontSize}px; color: ${fontColor}; text-align: ${alignment}; letter-spacing: ${spacing}px; width: 100%;">
            ${isError ? '⚠️ INTEGRITY_LEAK' : label}
          </span>
        </div>
      </div>
    `.trim();
  }

  /**
   * MASTER DISPATCHER
   */
  static renderCellHTML(item: ManifestEntity, options: CellOptions): string {
    const { runtimeValue, steps, isSelected, resolveAsset, manifest } = options;
    const compType = item.presentation?.component || 'knob';

    // 1. RACK BRANCH
    if (compType === 'rack') {
      return this.renderRackHTML(item, options);
    }

    // 2. ARCHITECTURAL BRANCH
    const isArchitectural = compType === 'container' || compType === 'group';
    if (isArchitectural) {
      return `
        <div class="architectural-cell" style="width: 100%; height: 100%; position: relative;">
          ${this.renderContainerHTML(item, options)}
        </div>
      `.trim();
    }

    // 2. PRIMITIVE BRANCH
    const variant = item.presentation?.variant || 'B_cyan';
    const parsed = parseVariant(variant);
    const size = (item.presentation?.scale as string) || parsed.size;
    const colorId = parsed.colorId;
    const compRadius = getComponentRadius(item);

    // ERA 7.2.3 - AESTHETIC RESOLUTION
    const rawStyle = item.presentation?.style || {};
    const resolvedStyle = ColorResolver.resolveStyle(rawStyle, manifest);

    const assetId = resolvedStyle.asset || item.presentation?.asset;
    const assetDef = manifest?.resources?.assets?.find((a) => a.id === assetId);
    const assetUrl = resolveAsset ? resolveAsset(assetId) : assetId;

    const inherited = getInheritedTypography(item.type as string, manifest);

    const commonProps = { 
      size, colorId, value: runtimeValue, id: item.id,
      isSelected: !!isSelected, isMain: true, style: resolvedStyle
    };

    const renderer = COMP_RENDERER_MAP[compType];
    let mainHTML = '';
    try {
      mainHTML = renderer 
        ? renderer(item, commonProps as Record<string, unknown>, { assetUrl: assetUrl as string, assetDef, steps, runtimeValue, inherited: inherited as Record<string, unknown>, manifest })
        : `<div class="unsupported-renderer">NO RENDERER: ${compType}</div>`;
    } catch (err: unknown) {
      const error = err as Error;
      console.error(`[CELL RENDERER] Fatal error in primitive ${item.presentation?.component}:`, error);
      mainHTML = `
        <div class="renderer-error" style="color: #ff3300; font-family: monospace; font-size: 8px; border: 1px solid #ff3300; padding: 4px; background: rgba(255,51,0,0.1);">
          ERROR: ${error.message}
        </div>
      `;
    }

    const attachments = item.presentation?.attachments || [];
    const stackOptions = { runtimeValue, steps, inherited, manifest, resolveAsset };

    const cellOffsetX = (item.presentation?.offsetX || 0) * 1.5;
    const cellOffsetY = (item.presentation?.offsetY || 0) * 1.5;

    const containerWidth = resolvedStyle.width !== undefined ? resolvedStyle.width : (compRadius * 2 * 1.5);
    const containerHeight = resolvedStyle.height !== undefined ? resolvedStyle.height : (compRadius * 2 * 1.5);

    return `
      <div class="control-cell variant-${variant}" style="--comp-radius: ${compRadius}px;">
        ${renderAttachmentStackHTML('top', attachments, stackOptions)}
        ${renderAttachmentStackHTML('bottom', attachments, stackOptions)}
        ${renderAttachmentStackHTML('left', attachments, stackOptions)}
        ${renderAttachmentStackHTML('right', attachments, stackOptions)}
        ${renderAttachmentStackHTML('center', attachments, stackOptions)}
        <div class="cell-main" style="width: ${containerWidth}px; height: ${containerHeight}px; transform: translate(calc(-50% + ${cellOffsetX}px), calc(-50% + ${cellOffsetY}px))">
          ${mainHTML}
        </div>
      </div>
    `.trim();
  }
}

/**
 * OMEGA UI CORE — CONTAINER RENDERER (Era 7.2.3)
 * ---------------------------------------------------------------------------
 * Static HTML generator for architectural module sections.
 * Ensures 100% parity across all rendering contexts.
 */

import { Presentation, OMEGA_Manifest, OmegaStyleNode } from '../types/manifest';
import { ColorResolver } from '../utils/ColorResolver';

interface ContainerRenderProps {
  id: string;
  label: string;
  variant: string;
  manifest?: OMEGA_Manifest;
  style?: OmegaStyleNode;
  isSelected?: boolean;
  isError?: boolean;
  resolveAsset?: (ref: string | undefined) => string | undefined;
}

export function renderContainerHTML(props: ContainerRenderProps): string {
  const { label, variant, manifest, style: aesthetics = {}, isSelected, isError, resolveAsset } = props;

  // 1. Resolve Genes (Aesthetic lookup)
  const libStyles = manifest?.ui?.styles?.container || [];
  const libStyle = libStyles.find((s) => s.id === variant) || { aesthetics: {} as Partial<Presentation> };
  const genetics = libStyle.aesthetics || {};

  // 2. Compute Surface Styles
  const bgAsset = aesthetics.asset || genetics.asset;
  const bgUrl = resolveAsset ? resolveAsset(bgAsset) : undefined;

  const rounding = (aesthetics as Record<string, unknown>).rounding as number ?? (genetics as Record<string, unknown>).rounding as number ?? 0;
  const borderWidth = (aesthetics as Record<string, unknown>).borderWidth as number ?? (genetics as Record<string, unknown>).borderWidth as number ?? 0;
  const opacity = (aesthetics as Record<string, unknown>).opacity as number ?? (genetics as Record<string, unknown>).opacity as number ?? 1.0;
  const bgColor = ColorResolver.resolve((aesthetics as Record<string, unknown>).color as string || (genetics as Record<string, unknown>).color as string, manifest);
  const borderColor = ColorResolver.resolve((aesthetics as Record<string, unknown>).indicatorColor as string || (genetics as Record<string, unknown>).indicatorColor as string, manifest);

  // 3. Compute Label Spatiality & Surface
  const labelX = (aesthetics as Record<string, unknown>).labelX as number ?? (genetics as Record<string, unknown>).labelX as number ?? 0;
  const labelY = (aesthetics as Record<string, unknown>).labelY as number ?? (genetics as Record<string, unknown>).labelY as number ?? 0;
  const labelW = (aesthetics as Record<string, unknown>).labelW as number ?? (genetics as Record<string, unknown>).labelW as number ?? 0;
  const labelH = (aesthetics as Record<string, unknown>).labelH as number ?? (genetics as Record<string, unknown>).labelH as number ?? 0;
  const labelBg = ColorResolver.resolve((aesthetics as Record<string, unknown>).labelBg as string || (genetics as Record<string, unknown>).labelBg as string, manifest);
  const labelRounding = (aesthetics as Record<string, unknown>).labelRounding as number ?? (genetics as Record<string, unknown>).labelRounding as number ?? 0;
  const labelPadding = (aesthetics as Record<string, unknown>).labelPadding as number ?? (genetics as Record<string, unknown>).labelPadding as number ?? 4;

  // 4. Compute Typography
  const font = (aesthetics as Record<string, unknown>).font as string || (genetics as Record<string, unknown>).font as string || 'Inter';
  const fontSize = (aesthetics as Record<string, unknown>).fontSize as number || (genetics as Record<string, unknown>).fontSize as number || 10;
  const fontColor = ColorResolver.resolve((aesthetics as Record<string, unknown>).fontColor as string || (genetics as Record<string, unknown>).fontColor as string || '#ffffff', manifest);
  const alignment = (aesthetics as Record<string, unknown>).alignment as string || (genetics as Record<string, unknown>).alignment as string || 'left';
  const flexAlign = alignment === 'left' ? 'flex-start' : (alignment === 'right' ? 'flex-end' : 'center');
  const spacing = (aesthetics as Record<string, unknown>).spacing as number || (genetics as Record<string, unknown>).spacing as number || 0;

  return `
    <div 
      class="industrial-container-surface ${isSelected ? 'selected' : ''} ${isError ? 'error' : ''}"
      style="
        position: absolute;
        inset: 0;
        background-color: ${bgColor};
        background-image: ${bgUrl ? `url(${bgUrl})` : 'none'};
        background-size: cover;
        background-position: center;
        border: ${borderWidth}px solid ${borderColor};
        border-radius: ${rounding}px;
        opacity: ${opacity};
        overflow: hidden;
      "
    >
      <div 
        class="container-label-fragment"
        style="
          position: absolute;
          left: ${labelX}px;
          top: ${labelY}px;
          width: ${labelW ? `${labelW}px` : 'auto'};
          height: ${labelH ? `${labelH}px` : 'auto'};
          background-color: ${labelBg};
          border-radius: ${labelRounding}px;
          padding: ${labelPadding}px;
          display: flex;
          align-items: center;
          justify-content: ${flexAlign};
          white-space: nowrap;
          z-index: 10;
        "
      >
        <span style="
          font-family: ${font};
          font-size: ${fontSize}px;
          color: ${fontColor};
          text-align: ${alignment};
          letter-spacing: ${spacing}px;
          line-height: 1;
          width: 100%;
        ">
          ${isError ? '⚠️ INTEGRITY_LEAK' : label}
        </span>
      </div>
    </div>
  `.trim();
}

/**
 * OMEGA UI CORE — Stateless Display Renderer (Era 7.2.3)
 * Single Source of Truth for Display HTML Structure.
 */

export interface DisplayProps {
  size: string;      // A, B, C, D
  colorId: string;   // cyan, orange, etc.
  mode: string;      // oled, lcd, led
  value: number;     // 0.0 to 1.0
  steps: number;     // Total steps to display
  id?: string;       // Canonical ID
  inheritedFont?: string | undefined;
  inheritedSize?: number | undefined;
  inheritedColor?: string | undefined;
  explicitGlassColor?: string; // Era 7.2.3 Custom Mode
  explicitTextColor?: string;  // Era 7.2.3 Custom Mode
}

export const renderDisplayHTML = (props: DisplayProps): string => {
  const { size, colorId, mode, value, steps, id, inheritedFont, inheritedSize, inheritedColor } = props;

  const displayValue = Math.round(value * (steps || 100));

  const contentColor = props.explicitTextColor || inheritedColor;

  const contentStyle = [
    inheritedFont ? `font-family: '${inheritedFont}'` : '',
    inheritedSize ? `font-size: ${inheritedSize}px` : '',
    contentColor ? `color: ${contentColor}` : ''
  ].filter(Boolean).join('; ');

  const glassStyle = props.explicitGlassColor ? `background-color: ${props.explicitGlassColor} !important; opacity: 0.3 !important;` : '';

  return `
    <div class="mini-display variant-${mode} size-${size} color-${colorId}" ${id ? `data-source="${id}"` : ''}>
      <div class="display-glass-overlay" style="${glassStyle}"></div>
      <div class="display-internal-glow"></div>
      <div class="display-scanlines"></div>
      <button class="display-btn minus" data-action="step-down">−</button>
      <div class="display-value" style="${contentStyle}">${displayValue}</div>
      <button class="display-btn plus" data-action="step-up">+</button>
    </div>
  `.trim();
};

'use client';

import React from 'react';
import { OmegaNode, OMEGA_Manifest, CellTemplate, ManifestEntity } from '../../types/manifest';
import { CellRenderer } from '../CellRenderer';
import { resolveNodeSemantics } from '../../uca/ucaSemantics';

interface UniversalRendererProps {
  node: OmegaNode;
  manifest: OMEGA_Manifest;
  depth?: number;
  catalog?: Record<string, CellTemplate>; 
  resolveAsset?: (id: string | undefined) => string | undefined;
}

/**
 * UNIVERSAL RENDERER (Phase 1 Experimental)
 * Recursive engine for UCA hierarchies.
 */
export function UniversalRenderer({ 
  node: rawNode, 
  manifest, 
  depth = 0,
  catalog = {},
  resolveAsset 
}: UniversalRendererProps) {
  // Resolve semantics (Template expansion + style inheritance)
  const node = resolveNodeSemantics(rawNode, { catalog });

  if (node.visible === false) return null;

  // 1. Dispatch Structural Nodes
  if (node.kind === 'rack' || node.kind === 'face' || node.kind === 'container') {
    return (
      <div 
        id={`uca-${node.id}`}
        className={`uca-node uca-${node.kind}`}
        style={{
          position: 'absolute',
          left: `${node.layout?.pos.x}px`,
          top: `${node.layout?.pos.y}px`,
          width: node.layout?.size?.width ? `${node.layout.size.width}px` : 'auto',
          height: node.layout?.size?.height ? `${node.layout.size.height}px` : 'auto',
          zIndex: node.layout?.zIndex || 0,
          pointerEvents: node.locked ? 'none' : 'auto'
        }}
      >
        {/* RECURSE: Render children within this coordinate space */}
        {node.children?.map(child => (
          <UniversalRenderer 
            key={child.id} 
            node={child} 
            manifest={manifest} 
            depth={depth + 1} 
            catalog={catalog}
            resolveAsset={resolveAsset}
          />
        ))}
      </div>
    );
  }

  // 2. Dispatch Atomic Cells
  if (node.kind === 'cell') {
    // Map OmegaNode back to a temporary ManifestEntity for CellRenderer parity
    const phantomEntity: ManifestEntity = {
      id: node.id,
      type: node.cellRef || 'knob',
      pos: node.layout?.pos || { x: 0, y: 0 },
      role: node.role || 'control',
      bind: node.bind || 'none',
      presentation: {
        tab: 'MAIN',
        component: 'knob', // Default, will be overridden by type resolution in CellRenderer
        variant: 'default',
        offsetX: 0,
        offsetY: 0,
        attachments: [],
        style: node.style
      }
    };

    const cellHTML = CellRenderer.renderCellHTML(phantomEntity, {
      skin: manifest.ui?.skin || 'industrial',
      zoom: 1.0,
      runtimeValue: 0, 
      steps: 100,
      manifest,
      resolveAsset
    });

    return (
      <div 
        className="uca-node uca-cell"
        style={{
          position: 'absolute',
          left: `${node.layout?.pos.x}px`,
          top: `${node.layout?.pos.y}px`,
          zIndex: node.layout?.zIndex || 0
        }}
      >
        {/* Render legacy primitive HTML */}
        <div 
          className="absolute inset-0 pointer-events-none"
          dangerouslySetInnerHTML={{ __html: cellHTML }}
        />

        {/* Recursive Layers / Children of the Cell */}
        {node.children?.map(child => (
          <UniversalRenderer 
            key={child.id} 
            node={child} 
            manifest={manifest} 
            depth={depth + 1} 
            catalog={catalog}
            resolveAsset={resolveAsset}
          />
        ))}
      </div>
    );
  }

  // 3. Dispatch Layers
  if (node.kind === 'layer') {
    // Simple layer rendering (labels, masks, etc.)
    return (
      <div 
        className="uca-node uca-layer"
        style={{
          position: 'absolute',
          left: `${node.layout?.pos.x}px`,
          top: `${node.layout?.pos.y}px`,
          color: node.style?.color,
          fontSize: node.style?.fontSize,
          opacity: node.style?.opacity
        }}
      >
        {node.role === 'label' && <span>{node.id}</span>}
      </div>
    );
  }

  return null;
}

/**
 * OMEGA UI CORE — Illustration Renderer (Fase 13)
 * Renders static images, logos, and technical drawings.
 */

export interface IllustrationProps {
  assetUrl?: string | undefined;
  size?: { w: number; h: number } | undefined;
  opacity?: number | undefined;
  id?: string | undefined;
  variant?: string | undefined;
}

export const renderIllustrationHTML = (props: IllustrationProps): string => {
  const { assetUrl, size, id, variant = 'contain' } = props;

  const w = size?.w || 40;
  const h = size?.h || 40;

  if (!assetUrl) {
    return `<div class="illustration-container illustration-missing" style="width: ${w * 1.5}px; height: ${h * 1.5}px;"></div>`;
  }

  return `
    <div 
        class="illustration-container variant-${variant}" 
        style="width: ${w * 1.5}px; height: ${h * 1.5}px;"
        ${id ? `data-source="${id}"` : ''}
    >
        <img 
          src="${assetUrl}" 
          style="width: 100%; height: 100%;" 
        />
    </div>
  `.trim();
};

/**
 * OMEGA UI CORE — Stateless Knob Renderer (Era 7.2.3)
 * Single Source of Truth for Knob HTML Structure.
 */

import { OmegaStyleNode } from '../types/manifest';

export interface KnobProps {
  size: string;          // A, B, C, D
  colorId: string;       // cyan, orange, etc.
  value: number;         // 0.0 to 1.0
  isSelected?: boolean;
  isMain?: boolean;
  id?: string;           // Canonical ID
  rotationOffset?: number; // Standard: -135
  rotationRange?: number;  // Standard: 270
  assetUrl?: string | undefined;       // URL del recurso (blob o external)
  frames?: number | undefined;         // Número de frames en el filmstrip
  orientation?: 'v' | 'h' | undefined; // Orientación del strip
  inheritedFont?: string | undefined;
  inheritedSize?: number | undefined;
  inheritedColor?: string | undefined;
  explicitMarkerColor?: string; // Era 7.2.3 Custom Mode
  style?: OmegaStyleNode; // [NEW] Era 7.2.3 Granular Style Node
}

export const renderKnobHTML = (props: KnobProps): string => {
  const { 
    size, 
    colorId, 
    value, 
    isSelected, 
    isMain, 
    id, 
    rotationOffset = -135, 
    rotationRange = 270,
    assetUrl,
    frames,
    orientation = 'v',
    style: customStyle
  } = props;

  // Canonical rotation formula
  const rotation = rotationOffset + (value * rotationRange);
  const selectedClass = isMain && isSelected ? 'selected' : '';
  const hasAssetClass = assetUrl ? 'has-asset' : '';

  const classes = [
    'knob-container',
    `size-${size}`,
    `color-${colorId}`,
    selectedClass,
    hasAssetClass
  ].filter(Boolean).join(' ');

  // ERA 7.2.3 - CSS VARIABLE INJECTION
  const markerColor = props.explicitMarkerColor || customStyle?.indicatorColor || customStyle?.color;

  const inlineStyles = [
    customStyle?.color ? `--omega-color-override: ${customStyle.color}` : '',
    markerColor ? `--omega-indicator-color: ${markerColor}` : '',
    customStyle?.shadow ? `--omega-shadow: ${customStyle.shadow}` : '',
    customStyle?.opacity !== undefined ? `opacity: ${customStyle.opacity}` : ''
  ].filter(Boolean).join('; ');

  const capStyle = customStyle?.color ? `background-color: ${customStyle.color} !important;` : '';

  let assetHTML = '';
  if (assetUrl) {
    let backgroundStyle = `background-image: url(${assetUrl});`;
    if (frames && frames > 1) {
        // Filmstrip Logic: Calculate which frame to show
        const frameIndex = Math.min(Math.floor(value * frames), frames - 1);
        const percent = (frameIndex / (frames - 1)) * 100;
        backgroundStyle += orientation === 'v' 
            ? `background-position: 0% ${percent}%;` 
            : `background-position: ${percent}% 0%;`;
    }
    assetHTML = `<div class="knob-asset filmstrip-${orientation}" style="${backgroundStyle}"></div>`;
  }

  const markerStyle = `--knob-rotation: ${rotation}deg; ${markerColor ? `background-color: ${markerColor} !important;` : ''}`;

  return `
    <div class="${classes}" ${id ? `data-source="${id}"` : ''} style="${inlineStyles}">
      <div class="knob-shadow-ring"></div>
      ${assetHTML}
      <div class="knob-cap" style="${capStyle}">
        <div class="knob-specular"></div>
      </div>
      <div class="knob-marker" style="${markerStyle}"></div>
    </div>
  `.trim();
};

/**
 * OMEGA UI CORE — Stateless LED Renderer (Era 7.2.3)
 * Single Source of Truth for LED HTML Structure.
 */

 export interface LedProps {
   size: string;      // A, B, C, D
   colorId: string;   // cyan, red, orange, etc.
   value: number;     // 0.0 to 1.0
   id?: string | undefined;       // Optional binding ID
   transform?: string | undefined; // Optional CSS transform
   explicitColor?: string | undefined; // [NEW] Era 7.2.3 Custom Color Override
   assetUrl?: string | undefined;
   frames?: number | undefined;
   orientation?: 'v' | 'h' | undefined;
 }

 export const renderLedHTML = (props: LedProps): string => {
   const { size, colorId, value, id, transform, assetUrl, frames, orientation = 'v' } = props;

   // Calculate visibility/glow based on value
   const isActive = value > 0.05;
   const opacity = 0.3 + (value * 0.7);

   // Industrial Pattern: .led.size-X.color-Y[.active]
   const classes = [
     'led',
     `size-${size}`,
     `color-${colorId}`,
     isActive ? 'active' : '',
     assetUrl ? 'has-asset' : ''
   ].filter(Boolean).join(' ');

   const style = [
     `opacity: ${opacity}`,
     props.explicitColor ? `--led-color: ${props.explicitColor}` : '',
     props.explicitColor ? `background-color: ${props.explicitColor} !important` : '',
     transform || ''
   ].filter(Boolean).join('; ');

   let assetHTML = '';
   if (assetUrl) {
     let backgroundStyle = `background-image: url(${assetUrl});`;
     if (frames && frames > 1) {
         const frameIndex = Math.min(Math.floor(value * frames), frames - 1);
         const percent = (frameIndex / (frames - 1)) * 100;
         backgroundStyle += orientation === 'v' 
             ? `background-position: 0% ${percent}%;` 
             : `background-position: ${percent}% 0%;`;
     }
     assetHTML = `<div class="led-asset filmstrip-${orientation}" style="${backgroundStyle}"></div>`;
   }

   return `
     <div class="${classes}" ${id ? `data-source="${id}"` : ''} style="${style}">
       ${assetHTML}
       <div class="led-glass-overlay"></div>
       <div class="led-internal-glow"></div>
     </div>
   `.trim();
 };

/**
 * OMEGA UI CORE — Stateless Port (Jack) Renderer (Era 7.2.3)
 * Single Source of Truth for Port HTML Structure.
 */

import { OmegaStyleNode } from '../types/manifest';

export interface PortProps {
  size: string;          // A, B, C, D
  colorId: string;       // Default color from variant (cyan, accent, etc.)
  value: number;         // Signal value 0.0 to 1.0
  isSelected?: boolean;
  isMain?: boolean;
  id?: string;           // Canonical ID for data attributes
  label?: string;        // For color inference
  explicitColor?: string; // Explicit color from manifest (B_cyan, neon_amber)
  inheritedFont?: string | undefined;
  inheritedSize?: number | undefined;
  inheritedColor?: string | undefined;
  customSignalColor?: string; // Era 7.2.3 Custom Mode
  style?: OmegaStyleNode; // [NEW] Era 7.2.3 Granular Style Node
}

/**
 * Infers the technical signal color based on ID/Label/Variant
 * Syced with VPC v1.1 standards.
 */
export const inferPortSignalColor = (id: string = '', label: string = '', explicitColor?: string): string => {
  if (explicitColor) return `var(--signal-${explicitColor.toLowerCase().replace('b_', '')}, var(--wb-primary))`;

  const searchStr = `${id} ${label}`.toLowerCase();

  if (searchStr.includes('midi')) return 'var(--signal-midi)';
  if (searchStr.includes('gate') || searchStr.includes('trig')) return 'var(--signal-gate)';
  if (searchStr.includes('cv') || searchStr.includes('mod')) return 'var(--signal-cv)';
  if (searchStr.includes('pitch') || searchStr.includes('freq') || searchStr.includes('out') || searchStr.includes('in')) return 'var(--signal-audio)';

  return 'var(--wb-primary)';
};

export const renderPortHTML = (props: PortProps): string => {
  const { size, colorId, value, isSelected, isMain, id, label, explicitColor, customSignalColor, style: customStyle } = props;

  const signalColor = customSignalColor || inferPortSignalColor(id, label, explicitColor);
  const opacity = 0.3 + (value * 0.7);
  const selectedClass = isMain && isSelected ? 'selected' : '';

  const classes = [
    'port-socket',
    `size-${size}`,
    `color-${colorId}`,
    selectedClass
  ].filter(Boolean).join(' ');

  // ERA 7.2.3 - CSS VARIABLE INJECTION
  const inlineStyles = [
    customStyle?.color ? `--omega-color-override: ${customStyle.color}` : '',
    customStyle?.opacity !== undefined ? `opacity: ${customStyle.opacity}` : '',
    customStyle?.shadow ? `--omega-shadow: ${customStyle.shadow}` : ''
  ].filter(Boolean).join('; ');

  const ledStyle = `background-color: ${signalColor}; opacity: ${opacity};`;

  return `<div class="${classes}" ${id ? `data-source="${id}"` : ''} style="${inlineStyles}"><div class="port-inner"><div class="port-led" style="${ledStyle}"></div></div></div>`;
};

/**
 * OMEGA Scope Primitive Renderer
 * Era 7.2.3 Industrial Aseptic
 */

export interface ScopeProps {
  variant: string;
  bind: string;
  size: { w: number; h: number };
  color?: string;
  font?: string | undefined;
}

export function renderScopeHTML(props: ScopeProps): string {
  const { variant, bind, size, color = 'var(--scope-color, #00ff88)' } = props;
  const zoom = 1.5;
  const w = size.w * zoom;
  const h = size.h * zoom;

  return `
    <div class="scope-display variant-${variant}" 
         data-bind="${bind}"
         style="--scope-width: ${w}px; --scope-height: ${h}px; --scope-color: ${color};">
        <canvas class="scope-canvas" width="${w}" height="${h}"></canvas>
        <div class="scope-grid"></div>
    </div>
  `;
}

/**
 * OMEGA UI CORE — Stateless Select Renderer (Era 7.2.3)
 * Single Source of Truth for Industrial Dropdown Menus.
 */

export interface SelectOption {
  label: string;
  value: string | number;
}

export interface SelectProps {
  size: string;      // A, B, C, D
  colorId: string;   // cyan, orange, etc.
  value: number;     // Normalized index (0.0 to 1.0)
  options?: (string | SelectOption)[]; // List of available options or labels
  id?: string;       // Canonical ID
}

export const renderSelectHTML = (props: SelectProps): string => {
  const { size, colorId, value, options = [], id } = props;

  // Resolve current label based on normalized value
  const labels = options.length > 0 
    ? options.map(opt => typeof opt === 'string' ? opt : opt.label) 
    : ['NO OPTIONS'];

  const currentIndex = Math.min(labels.length - 1, Math.floor(value * labels.length));
  const currentLabel = labels[currentIndex];

  return `
    <div class="mini-select size-${size} color-${colorId}" ${id ? `data-source="${id}"` : ''}>
      <div class="select-value">${(currentLabel || '').toUpperCase()}</div>

      <div class="select-arrow">▼</div>
    </div>
  `.trim();
};

/**
 * ⚠️ OMEGA UI CORE — SEQUENCE RENDERER (Era 7.2.3)
 * ---------------------------------------------------------------------------
 * Specialized renderer for filmstrip-based components (Sequence Layer).
 * Handles frame clipping, orientation mapping, and state-based positioning.
 * ---------------------------------------------------------------------------
 */



export interface SequenceProps {
    assetUrl?: string;
    value: number;
    frames: number;
    frameWidth: number;
    frameHeight: number;
    orientation: 'v' | 'h';
    opacity: number;
    padding?: number[];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    style?: Record<string, any>;
}

export const renderSequenceHTML = (props: SequenceProps): string => {
    const { 
        assetUrl, value, frames, frameWidth, frameHeight, 
        orientation, opacity, style 
    } = props;

    const renderWidth = style?.width || frameWidth;
    const renderHeight = style?.height || frameHeight;

    if (!assetUrl) {
        return `
            <div style="width: ${renderWidth}px; height: ${renderHeight}px; border: 1px dashed #555; display: flex; align-items: center; justify-content: center;">
                <span style="font-size: 6px; color: #555; font-family: monospace; font-weight: 900;">NO_SEQUENCE</span>
            </div>
        `;
    }

    const backgroundSize = orientation === 'v' 
        ? `100% auto` 
        : `auto 100%`;

    // Polarity handling (Era 7.2.3 Industrial Logic)
    const effectiveValue = props.style?.polarity === 'inverted' ? (1 - value) : value;

    const frameIndex = Math.round(effectiveValue * (frames - 1));
    const percent = frames > 1 ? (frameIndex / (frames - 1)) * 100 : 0;

    const backgroundPos = orientation === 'v' 
        ? `0% ${percent}%` 
        : `${percent}% 0%`;

    return `
        <div class="omega-sequence-layer" style="
            width: ${renderWidth}px;
            height: ${renderHeight}px;
            background-image: url('${assetUrl}');
            background-position: ${backgroundPos};
            background-size: ${backgroundSize};
            background-repeat: no-repeat;
            opacity: ${opacity};
            position: relative;
            pointer-events: none;
        ">
        </div>
    `;
};

/**
 * OMEGA UI CORE — Stateless Slider Renderer (Era 7.2.3)
 * Single Source of Truth for Slider HTML Structure.
 */

 import { OmegaStyleNode } from '../types/manifest';

 export interface SliderProps {
   type: 'slider-v' | 'slider-h';
   size: string;      // A, B, C, D
   colorId: string;   // cyan, orange, etc.
   value: number;     // 0.0 to 1.0
   id?: string;       // Canonical ID
   inheritedFont?: string | undefined;
   inheritedSize?: number | undefined;
   inheritedColor?: string | undefined;
   style?: OmegaStyleNode; // [NEW] Era 7.2.3 Granular Style Node
   assetUrl?: string | undefined;
   frames?: number | undefined;
   orientation?: 'v' | 'h' | undefined;
 }

 export const renderSliderHTML = (props: SliderProps): string => {
   const { 
     type, size, colorId, value, id, style: customStyle,
     assetUrl, frames, orientation = 'v'
   } = props;
   const isHoriz = type === 'slider-h';

   // Logic synced with VPC v1.1
   const railStyle = isHoriz 
     ? `width: calc(${value * 100}% - 4px)` 
     : `height: calc(${value * 100}% - 4px)`;

   const capStyle = isHoriz 
     ? `left: calc(${value * 90}%)` 
     : `bottom: calc(${value * 90}%)`;

   // ERA 7.2.3 - CSS VARIABLE INJECTION
   const inlineStyles = [
     customStyle?.color ? `--omega-color-override: ${customStyle.color}` : '',
     customStyle?.indicatorColor ? `--omega-indicator-color: ${customStyle.indicatorColor}` : '',
     customStyle?.opacity !== undefined ? `opacity: ${customStyle.opacity}` : '',
     customStyle?.shadow ? `--omega-shadow: ${customStyle.shadow}` : ''
   ].filter(Boolean).join('; ');

   let assetHTML = '';
   if (assetUrl) {
     let backgroundStyle = `background-image: url(${assetUrl});`;
     if (frames && frames > 1) {
         const frameIndex = Math.min(Math.floor(value * frames), frames - 1);
         const percent = (frameIndex / (frames - 1)) * 100;
         backgroundStyle += orientation === 'v' 
             ? `background-position: 0% ${percent}%;` 
             : `background-position: ${percent}% 0%;`;
     }
     assetHTML = `<div class="slider-asset filmstrip-${orientation}" style="${backgroundStyle}"></div>`;
   }

   return `
     <div class="slider-wrapper ${type} size-${size} color-${colorId} ${assetUrl ? 'has-asset' : ''}" ${id ? `data-source="${id}"` : ''} style="${inlineStyles}">
       ${assetHTML}
       <div class="slider-rail-active" style="${railStyle}; background-color: var(--omega-indicator-color) !important;"></div>
       <div class="slider-cap" style="${capStyle}; background-color: var(--omega-color-override) !important;"></div>
     </div>
   `.trim();
 };

