 * Physical dimensions and geometric mapping for industrial components.
 */

import type { ManifestEntity } from '../../types/manifest';
import { parseVariant } from './VariantParser';

const RADIUS_MAP: Record<string, Record<string, number>> = {
  knob: { A: 24, B: 18, C: 12, D: 9 },
  port: { A: 21, B: 18, C: 15, D: 12 },
  display: { A: 16.5, B: 13, C: 10, D: 7 },
  led: { A: 6, B: 4, C: 2.5, D: 1.5 },
  slider: { A: 6, B: 6, C: 6, D: 6 },
  switch: { A: 16, B: 12, C: 10, D: 8 },
  stepper: { A: 12, B: 9, C: 7, D: 6 },
  select: { A: 12, B: 12, C: 12, D: 12 }
};

export function getComponentRadius(item: ManifestEntity): number {
  const { size } = parseVariant(item.presentation?.variant);
  const comp = item.presentation?.component || 'knob';
  const typeKey = comp.includes('slider') ? 'slider' : comp;

  const sizeMap = RADIUS_MAP[typeKey] || RADIUS_MAP.knob;
  const radius = sizeMap ? sizeMap[size] : 12;

  return radius || 12;
}

import type { OMEGA_Manifest } from '../../types/manifest.js';

/**
 * OMEGA Typography Inheritance Engine
 * ---------------------------------------------------------------------------
 * Logic for resolving global design tokens based on component categories.
 */
export interface InheritedTypography {
  font?: string;
  size?: number;
  color?: string;
}

export const getInheritedTypography = (compType: string, manifest?: OMEGA_Manifest): InheritedTypography => {
  const mapping = manifest?.ui?.typography;
  if (!mapping) return {};

  let cat: 'headings' | 'labels' | 'displays' | 'technical' = 'labels';

  // Rule-based category resolution
  if (compType === 'display' || compType === 'scope' || compType === 'terminal') {
    cat = 'displays';
  } else if (compType === 'port' || compType === 'knob' || compType === 'slider-v' || compType === 'slider-h' || compType === 'switch') {
    cat = 'labels';
  } else if (compType === 'stepper' || compType === 'button' || compType === 'push') {
    cat = 'labels'; // Or headings depending on branding
  }

  return mapping[cat] || {};
};

/**
 * OMEGA Variant Parser (Era 7.2.3)
 * Unified logic to extract size and color information from industrial variant strings.
 */

export interface ParsedVariant {
  size: string;
  colorId: string;
}

export function parseVariant(variant: string | undefined): ParsedVariant {
  const v = variant || 'B_cyan';
  const parts = v.split('_');

  let size = parts[0] || 'B';

  // Industrial exceptions for specific millimetric sizes
  if (v.includes('_3mm')) size = 'D';
  if (v.includes('_5mm')) size = 'C';

  // Color extraction (filter out size and technical suffixes)
  const colorId = parts.length > 1 
    ? parts.filter(p => p !== size && p !== '3mm' && p !== '5mm').join('_') 
    : 'cyan';

  return { size, colorId };
}

