/**
 * UCA SEMANTICS (Phase 1)
 * Rules for node resolution, template expansion, and style inheritance.
 */

export interface ResolutionContext {
  catalog: Record<string, CellTemplate>;
  parentStyle?: OmegaStyleNode;
}

/**
 * resolveNodeSemantics
 * Expands a node based on its template and applies the inheritance chain.
 */
export function resolveNodeSemantics(
  node: OmegaNode, 
  ctx: ResolutionContext
): OmegaNode {
  let resolved: OmegaNode = { ...node };

  // 1. TEMPLATE EXPANSION
  if (node.kind === 'cell' && node.cellRef) {
    const template = ctx.catalog[node.cellRef];
    if (template) {
      // Merge: Template Base -> Instance Overrides
      resolved = {
        ...template.baseNode,
        ...node,
        // Ensure children are merged (Template layers + Instance children)
        children: [
          ...(template.baseNode.children || []),
          ...(node.children || [])
        ],
        // Merge styles
        style: {
          ...template.baseNode.style,
          ...node.style
        }
      };
    }
  }

  // 2. STYLE INHERITANCE (Era 7.2.3 Genetic Propagation)
  if (ctx.parentStyle) {
    resolved.style = {
      font: resolved.style?.font || ctx.parentStyle.font,
      fontColor: resolved.style?.fontColor || ctx.parentStyle.fontColor,
      // Color tokens don't usually inherit unless they are generic
      ...resolved.style
    };
  }

  // 3. RECURSIVE RESOLUTION
  if (resolved.children) {
    resolved.children = resolved.children.map(child => 
      resolveNodeSemantics(child, {
        ...ctx,
        parentStyle: resolved.style
      })
    );
  }

  return resolved;
}

import { OMEGA_Manifest } from '@/types/manifest';

/**
 * OMEGA COLOR RESOLUTION ENGINE (Era 7.2.3)
 * The single source of truth for translating theme tokens to HEX across all renderers.
 */
export class ColorResolver {
  /**
   * Translates a color token or value into a physical HEX color.
   */
  static resolve(col: string | undefined, manifest?: OMEGA_Manifest): string {
    if (!col || col === 'none') return 'transparent';
    if (col === 'transparent' || col === 'white' || col === 'black') return col;

    // ERA 7.2.3 - Hybrid Token/Alpha Resolution (DRY Philosophy)
    let baseColor = col;
    let alpha = 1;

    if (col.includes('/')) {
      const parts = col.split('/');
      baseColor = parts[0];
      alpha = parseFloat(parts[1]) || 1;
    }

    const resolveBase = (c: string): string => {
      if (c.startsWith('#') || c.startsWith('rgba') || c.startsWith('rgb')) return c;

      // Era 7.2.3 Canonical Defaults
      const defaults: Record<string, string> = {
        primary: '#00f2ff',
        secondary: '#ff8c00',
        utility: '#a0a0a0',
        feedback: '#32cd32',
        surface: '#121416',
        hardware: '#777777',
        chassis: '#1a1a1a',
        text: '#ffffff',
        glow: '#00f2ff',
        glass: 'rgba(255,255,255,0.05)',
        warning: '#ff3300',
        highlight: '#ffffff',
        weak: '#555555'
      };

      const palette = manifest?.ui?.palette || {};
      const colors = manifest?.ui?.colors || {};
      const fullPalette: Record<string, string> = { ...defaults, ...palette, ...colors };
      return fullPalette[c] || c;
    };

    const resolvedHex = resolveBase(baseColor);
    const hasExplicitAlpha = col.includes('/');

    // Apply Alpha if explicitly requested or if it's not 1.0
    if (hasExplicitAlpha || alpha < 1) {
      if (resolvedHex.startsWith('#')) {
        const r = parseInt(resolvedHex.slice(1, 3), 16);
        const g = parseInt(resolvedHex.slice(3, 5), 16);
        const b = parseInt(resolvedHex.slice(5, 7), 16);
        return `rgba(${r}, ${g}, ${b}, ${alpha})`;
      }
      if (resolvedHex.startsWith('rgba')) {
        return resolvedHex.replace(/[\d.]+\)$/, `${alpha})`);
      }
    }

    return resolvedHex;
  }

  /**
   * Recursively resolves all color properties in a style node.
   */
  static resolveStyle<T extends Record<string, unknown>>(style: T | undefined, manifest?: OMEGA_Manifest): T {
    if (!style) return {} as T;
    const resolved = { ...style } as Record<string, unknown>;

    // List of all 13 properties that are known to contain color tokens
    const colorProps = [
      'color', 'indicatorColor', 'glowColor', 'glassColor', 'fontColor', 
      'shadowColor', 'ambientColor', 'specularColor', 'warningColor',
      'borderColor', 'backgroundColor', 'activeColor', 'hoverColor'
    ];

    colorProps.forEach(prop => {
      if (typeof resolved[prop] === 'string') {
        resolved[prop] = ColorResolver.resolve(resolved[prop] as string, manifest);
      }
    });

    return resolved as T;
  }
}

import { OMEGA_Manifest } from '../types/manifest';
import { ValidationService } from './validationService';
import { ValidationIssue } from '../types/validation';
import { OmegaContract } from './wasmLoader';

export interface AuditResult {
  isCompliant: boolean;
  score: number; // 0-100
  status: 'DRAFT' | 'CERTIFIED' | 'CRITICAL_FAIL';
  checks: {
    governance: boolean;
    technical: boolean;
    aesthetic: boolean;
    integrity: boolean;
  };
  details: string[];
  issues: ValidationIssue[];
  fingerprint?: string; 
  isHashMatched?: boolean;
}

export class AuditService {
  static performFullAudit(manifest: OMEGA_Manifest, contract: OmegaContract | null = null): AuditResult {
    const issues = ValidationService.validate(manifest, contract);
    const details: string[] = [];

    let governance = true;
    let technical = true;
    let aesthetic = true;
    let integrity = true;

    // 1. CHEQUEO DE GOBERNANZA Y REGLAS DE ORO
    const fatalIssues = issues.filter(i => i.severity === 'critical');
    const errorIssues = issues.filter(i => i.severity === 'error');

    if (fatalIssues.length > 0 || errorIssues.length > 0) {
      governance = false;
      details.push(`CRITICAL: ${fatalIssues.length + errorIssues.length} fallos graves detectados.`);
    }

    // 2. CHEQUEO DE INTEGRIDAD ESPACIAL
    const integrityIssues = issues.filter(i => i.keyword === 'era7_integrity');
    if (integrityIssues.length > 0) {
      integrity = false;
      details.push(`INTEGRITY: ${integrityIssues.length} violaciones de límites físicos.`);
    }

    // 3. CHEQUEO DE AUDITORÍA PRO-MASTER
    const auditIssues = issues.filter(i => i.severity === 'audit');
    if (auditIssues.length > 0) {
      aesthetic = false;
      details.push(`PRO-MASTER: ${auditIssues.length} detalles de refinamiento pendientes.`);
    }

    // 4. CHEQUEO TÉCNICO GENERAL
    const techIssues = issues.filter(i => i.severity === 'warning');
    if (techIssues.length > 0) {
      technical = false;
      details.push(`TECHNICAL: ${techIssues.length} advertencias de configuración.`);
    }

    // CALCULO FINAL DE SCORE
    const hasCritical = fatalIssues.length > 0;
    const isCompliant = !hasCritical && errorIssues.length === 0;
    let score = hasCritical ? 0 : 100;

    if (!hasCritical) {
      score -= errorIssues.length * 15;
      score -= issues.filter(i => i.severity === 'warning').length * 5;
      score -= issues.filter(i => i.severity === 'audit').length * 2;
    }

    score = Math.max(0, score);

    let status: AuditResult['status'] = 'CERTIFIED';
    if (hasCritical || !isCompliant) status = 'CRITICAL_FAIL';
    else if (score < 90) status = 'DRAFT';

    return {
      isCompliant,
      score,
      status,
      checks: { 
        governance, 
        technical, 
        aesthetic: aesthetic && auditIssues.length === 0, 
        integrity 
      },
      details,
      issues
    };
  }

  static generateCertificationReport(manifest: OMEGA_Manifest, audit: AuditResult): string {
    const date = new Date().toISOString().split('T')[0];
    const time = new Date().toTimeString().split(' ')[0];

    return `# OMEGA ERA 7.2.3 - CERTIFICATE OF CONFORMITY

## [ REPORT SUMMARY ]
- **Module ID**: ${manifest.id}
- **Commercial Name**: ${manifest.metadata?.name || 'Unknown'}
- **Engine Version**: ${manifest.schemaVersion || '7.2.3'}
- **Audit Timestamp**: ${date} ${time}
- **Certification Status**: ${audit.status}
- **Industrial Score**: ${audit.score}/100

## [ ARCHITECTURAL AUDIT ]
- **Governance (Golden Rules)**: ${audit.checks.governance ? 'PASSED ✅' : 'CRITICAL ❌'}
- **Structural Integrity**: ${audit.checks.integrity ? 'PASSED ✅' : 'VIOLATION ❌'}
- **Technical Standards**: ${audit.checks.technical ? 'PASSED ✅' : 'WARNING ⚠️'}
- **Pro-Master Refinement**: ${audit.checks.aesthetic ? 'CERTIFIED ✨' : 'PENDING 🛠️'}

## [ DETAILED INSPECTION LOG ]
${audit.issues.map(i => `> [${i.severity.toUpperCase()}] ${i.message}`).join('\n') || '> No critical issues detected.'}

---
*Generated by OMEGA Compliance Engine v7.2.3 — Aseptic Industrial Standard*
`;
  }

  /**
   * Triggers a browser download for the certification report.
   * Keeps components aseptic by handling DOM effects here.
   */
  static downloadCertificationReport(manifest: OMEGA_Manifest, audit: AuditResult) {
    const report = this.generateCertificationReport(manifest, audit);
    const blob = new Blob([report], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `CERTIFICATE_${manifest.id}_${new Date().getTime()}.md`;
    a.click();
    URL.revokeObjectURL(url);
  }
}

/**
 * OMEGA CAD Export Service (v7.2.3)
 * Generates technical industrial blueprints (SVG) from manifests.
 */
import { OMEGA_Manifest } from '../types/manifest';

export interface CADOptions {
  skin: string;
  drillLayer: boolean;
  silkscreenLayer: boolean;
  dimensions: boolean;
  resolveAsset?: (id: string) => string | undefined; // Base64 or URL
}

const PIXELS_TO_MM = 0.33866; // 1 HP = 5.08mm = 15px

export class CADExportService {
  static generateSVGBlueprint(manifest: OMEGA_Manifest, options: CADOptions): string {
    const { skin, drillLayer, silkscreenLayer, dimensions, resolveAsset } = options;
    const hp = manifest.metadata?.rack?.hp || 12;
    const rackWidthPx = hp * 15 * 1.5;
    const rackHeightPx = (manifest.ui?.dimensions?.height || (manifest.metadata?.rack?.height_mode === 'compact' ? 140 : 420)) * 1.5;
    const margin = 100; // Larger margin for annotations

    const containers = manifest.ui?.layout?.containers || [];
    const elements = [
      ...(manifest.ui?.controls || []).map(e => ({ ...e, isJack: false })),
      ...(manifest.ui?.jacks || []).map(e => ({ ...e, isJack: true }))
    ];

    const skinColor = skin === 'carbon' ? '#080808' : skin === 'minimal' ? '#f0f0f0' : skin === 'glass' ? '#1a1a1a' : '#111111';
    const accentColor = skin === 'minimal' ? '#000000' : '#00f0ff';

    const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${rackWidthPx + margin * 2}" height="${rackHeightPx + margin * 2}" viewBox="0 0 ${rackWidthPx + margin * 2} ${rackHeightPx + margin * 2}">
      <rect width="100%" height="100%" fill="${silkscreenLayer && !drillLayer ? skinColor : '#000'}" />

      <g transform="translate(${margin}, ${margin})">
        <!-- RACK CHASSIS -->
        <rect width="${rackWidthPx}" height="${rackHeightPx}" fill="${skinColor}" stroke="${accentColor}" stroke-width="1" rx="2" opacity="${silkscreenLayer ? 1 : 0.2}" />

        <!-- TECHNICAL HEADER -->
        <text x="0" y="-40" fill="${accentColor}" font-family="monospace" font-size="12" font-weight="900">OMEGA CAD [ ${manifest.id.toUpperCase()} ]</text>
        <text x="0" y="-25" fill="rgba(255,255,255,0.4)" font-family="monospace" font-size="8">FORMAT: Era 7.2.3 Industrial | CALIBRATION: 1px = ${PIXELS_TO_MM}mm</text>

        ${silkscreenLayer ? `
        <!-- CONTAINERS & BRANDING -->
        ${containers.map(c => {
          const bgUrl = resolveAsset && c.asset ? resolveAsset(c.asset) : null;
          return `
          <g>
            <rect x="${c.pos.x * 1.5}" y="${c.pos.y * 1.5}" width="${(typeof c.size.w === 'number' ? c.size.w : 100) * 1.5}" height="${c.size.h * 1.5}" fill="${c.color || 'rgba(255,255,255,0.02)'}" stroke="rgba(255,255,255,0.1)" stroke-width="0.5" />
            ${bgUrl ? `<image x="${c.pos.x * 1.5}" y="${c.pos.y * 1.5}" width="${(typeof c.size.w === 'number' ? c.size.w : 100) * 1.5}" height="${c.size.h * 1.5}" href="${bgUrl}" />` : ''}
            <text x="${c.pos.x * 1.5 + 5}" y="${c.pos.y * 1.5 + 10}" fill="rgba(255,255,255,0.3)" font-family="monospace" font-size="7" font-weight="900">${c.label.toUpperCase()}</text>
          </g>`;
        }).join('')}
        ` : ''}

        <!-- ELEMENTS -->
        ${elements.map(e => {
          const ex = e.pos.x * 1.5;
          const ey = e.pos.y * 1.5;
          const assetId = e.presentation.asset;
          const assetUrl = resolveAsset && assetId ? resolveAsset(assetId) : null;

          return `
          <g transform="translate(${ex}, ${ey})">
            ${drillLayer ? `
              <!-- DRILL CENTER MARK -->
              <line x1="-10" x2="10" y1="0" y2="0" stroke="#ff0000" stroke-width="0.5" />
              <line x1="0" x2="0" y1="-10" y2="10" stroke="#ff0000" stroke-width="0.5" />
              <circle r="${e.isJack ? 6 * 1.5 : 4 * 1.5}" fill="none" stroke="#ff0000" stroke-width="0.2" />
            ` : ''}

            ${silkscreenLayer ? `
              <!-- VISUAL PRIMITIVE -->
              ${assetUrl ? `<image x="-20" y="-20" width="40" height="40" href="${assetUrl}" />` : `
                <circle r="${e.isJack ? 10 : 15}" fill="none" stroke="${accentColor}" stroke-width="1" />
              `}
              <text y="30" fill="${accentColor}" font-family="monospace" font-size="8" font-weight="900" text-anchor="middle">${e.label?.toUpperCase() || e.id.toUpperCase()}</text>
              ${dimensions ? `<text y="40" fill="rgba(255,255,255,0.4)" font-family="monospace" font-size="5" text-anchor="middle">${Math.round(ex * PIXELS_TO_MM)}mm , ${Math.round(ey * PIXELS_TO_MM)}mm</text>` : ''}
            ` : ''}
          </g>`;
        }).join('')}
      </g>
    </svg>`;

    return svg;
  }
}

/**
 * OMEGA Contract Service (v7.2.3)
 * Handles generation of technical contracts (enums, schema IDs) from manifests.
 */
import { OMEGA_Manifest } from '../types/manifest';

export class ContractService {
  /**
   * Generates a TypeScript source file containing Enums for all parameters and ports.
   * This is the "Numeric Authority" for the C++ engine.
   */
  static generateTypeScriptContract(manifest: OMEGA_Manifest): string {
    const controls = manifest.ui?.controls || [];
    const jacks = manifest.ui?.jacks || [];
    const name = manifest.metadata?.name || 'OmegaModule';
    const safeName = name.replace(/[^a-zA-Z0-9]/g, '');

    let content = `/**\n * OMEGA Technical Contract: ${name}\n * Generated: ${new Date().toISOString()}\n * DO NOT EDIT MANUALLY — Exported from OMEGA Manifest Editor\n */\n\n`;

    // ParamId Enum
    content += `export enum ${safeName}ParamId {\n`;
    controls.forEach((c, idx) => {
      const id = c.id.toUpperCase().replace(/[^A-Z0-9_]/g, '_');
      content += `  ${id} = ${idx}, // ${c.label || c.id}\n`;
    });
    content += `}\n\n`;

    // PortId Enum
    content += `export enum ${safeName}PortId {\n`;
    jacks.forEach((j, idx) => {
      const id = j.id.toUpperCase().replace(/[^A-Z0-9_]/g, '_');
      content += `  ${id} = ${idx}, // ${j.label || j.id}\n`;
    });
    content += `}\n\n`;

    // Metadata Export
    content += `export const ${safeName}Metadata = {\n`;
    content += `  HP: ${manifest.metadata?.rack?.hp || 12},\n`;
    content += `  VERSION: "${manifest.metadata?.version || '1.0.0'}",\n`;
    content += `  CANONICAL_ID: "${manifest.id}"\n`;
    content += `};\n`;

    return content;
  }

  /**
   * Generates a C++ Header file for direct inclusion in the OMEGA Engine.
   */
  static generateCppContract(manifest: OMEGA_Manifest): string {
    const controls = manifest.ui?.controls || [];
    const jacks = manifest.ui?.jacks || [];
    const name = manifest.metadata?.name || 'OmegaModule';
    const safeName = name.toUpperCase().replace(/[^A-Z0-9]/g, '_');

    let content = `/**\n * OMEGA Technical Contract: ${name}\n * Generated: ${new Date().toISOString()}\n */\n\n`;
    content += `#pragma once\n\n`;
    content += `namespace ${safeName}_CONTRACT {\n\n`;

    content += `  enum ParamId {\n`;
    controls.forEach((c, idx) => {
      const id = c.id.toUpperCase().replace(/[^A-Z0-9_]/g, '_');
      content += `    ${id} = ${idx}, // ${c.label || c.id}\n`;
    });
    content += `  };\n\n`;

    content += `  enum PortId {\n`;
    jacks.forEach((j, idx) => {
      const id = j.id.toUpperCase().replace(/[^A-Z0-9_]/g, '_');
      content += `    ${id} = ${idx}, // ${j.label || j.id}\n`;
    });
    content += `  };\n\n`;

    content += `  static constexpr int HP = ${manifest.metadata?.rack?.hp || 12};\n`;
    content += `  static const char* VERSION = "${manifest.metadata?.version || '1.0.0'}";\n`;

    content += `}\n`;

    return content;
  }

  /**
   * Triggers a browser download for the generated contract.
   * Keeps components aseptic by handling DOM effects here.
   */
  static downloadContract(manifest: OMEGA_Manifest, format: 'ts' | 'cpp') {
    const content = format === 'ts' 
      ? this.generateTypeScriptContract(manifest)
      : this.generateCppContract(manifest);

    const filename = format === 'ts' ? 'schema_ids.ts' : 'OmegaRegistry.h';
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }
}

/**
 * OMEGA INPUT SIGNAL SERVICE - ERA 7.1
 * Manages virtual signal generators for input port simulation.
 */

export type SignalType = 'sine' | 'square' | 'saw' | 'triangle' | 'noise' | 'lfo_slow' | 'static';

export interface VirtualSignal {
  type: SignalType;
  frequency: number; // Hz
  amplitude: number; // 0.0 to 1.0
  offset: number;
}

class InputSignalService {
  private activeSignals: Record<string, VirtualSignal> = {};
  private startTime: number = Date.now();

  setSignal(portId: string, signal: VirtualSignal | null) {
    if (!signal) {
      delete this.activeSignals[portId];
    } else {
      this.activeSignals[portId] = signal;
    }
  }

  getSignalValue(portId: string): number {
    const sig = this.activeSignals[portId];
    if (!sig) return 0;

    const t = (Date.now() - this.startTime) / 1000;
    const freq = sig.frequency;
    const amp = sig.amplitude;
    const off = sig.offset;

    switch (sig.type) {
      case 'sine':
        return off + amp * Math.sin(2 * Math.PI * freq * t);
      case 'square':
        return off + (Math.sin(2 * Math.PI * freq * t) >= 0 ? amp : -amp);
      case 'saw':
        return off + amp * (2 * (t * freq - Math.floor(0.5 + t * freq)));
      case 'noise':
        return off + (Math.random() * 2 - 1) * amp;
      case 'lfo_slow':
        return off + amp * Math.sin(2 * Math.PI * 0.5 * t); // 0.5Hz LFO
      case 'static':
        return off + amp;
      default:
        return 0;
    }
  }

  getActiveSignal(portId: string): VirtualSignal | null {
    return this.activeSignals[portId] || null;
  }
}

export const inputSignalService = new InputSignalService();

/**
 * OMEGA Integrity Service (v7.2.3)
 * Provides cryptographic hashing for manifest firmware integrity checks.
 */
import { OMEGA_Manifest } from '../types/manifest';

export class IntegrityService {
  /**
   * Generates a SHA-256 hash of any object.
   * Uses canonical normalization (alphabetical key sorting and minification).
   */
  static async generateHash(obj: Record<string, unknown>): Promise<string> {
    // 1. Remove hash/firmwareHash property if present to calculate clean hash
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { hash, firmwareHash, ...cleanObj } = obj;

    // Canonical Normalization: Recursive Key Sorting
    const sortObject = (o: unknown): unknown => {
      if (o === null || typeof o !== 'object') return o;
      if (Array.isArray(o)) return o.map(sortObject);

      const record = o as Record<string, unknown>;
      return Object.keys(record).sort().reduce((acc: Record<string, unknown>, key: string) => {
        acc[key] = sortObject(record[key]);
        return acc;
      }, {});
    };

    const canonicalJson = JSON.stringify(sortObject(cleanObj));
    const encoder = new TextEncoder();
    const data = encoder.encode(canonicalJson);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  }

  /**
   * Generates a SHA-256 hash of the manifest object (alias for backward compatibility).
   */
  static async generateManifestHash(manifest: OMEGA_Manifest): Promise<string> {
    return this.generateHash(manifest as unknown as Record<string, unknown>);
  }

  /**
   * Verifies if an object matches a given hash.
   */
  static async verifyIntegrity(obj: Record<string, unknown>, expectedHash: string): Promise<boolean> {
    const currentHash = await this.generateHash(obj);
    return currentHash === expectedHash;
  }
}

