import { OMEGA_Manifest, ManifestEntity } from '../../omega-ui-core/types/manifest';
import { ValidationIssue } from '../../types/validation';
import { OmegaContract } from '../wasmLoader';

export class IndustrialRules {
  static validate(manifest: OMEGA_Manifest, contract: OmegaContract | null): ValidationIssue[] {
    const issues: ValidationIssue[] = [];
    if (!manifest.schemaVersion?.startsWith('7')) return issues;

    const hp = manifest.metadata?.rack?.hp || 12;
    const rackWidth = hp * 15;
    const rackHeight = manifest.ui.dimensions?.height || 420;

    const containers = manifest.ui.layout?.containers || [];
    const activePlanes = manifest.ui.layout?.planes || ['MAIN'];
    const usedIds = new Set<string>();

    // ERA 7.2.3 - MANDATORY INFRASTRUCTURE
    if (containers.length === 0) {
      issues.push({
        path: '/ui/layout/containers',
        message: `CRITICAL FAIL: No existen contenedores. Todo módulo OMEGA requiere al menos una placa base (Container).`,
        keyword: 'era7_infrastructure',
        severity: 'critical'
      });
    }

    if (hp % 2 !== 0) {
      issues.push({
        path: '/metadata/rack/hp',
        message: `PRO-MASTER: HP impar (${hp}). Se recomienda HP par para estética Eurorack.`,
        keyword: 'era7_style',
        severity: 'audit'
      });
    }

    const containerTabMap = new Map(containers.map(c => [c.id, c.tab || 'MAIN']));
    const availableAssets = new Set(manifest.resources?.assets?.map(a => a.id) || []);

    // CHEQUEO DE ACTIVOS (Fase 13 — AGGRESSIVE)
    if (manifest.metadata?.icon && !availableAssets.has(manifest.metadata.icon)) {
        issues.push({
            path: '/metadata/icon',
            message: `CRITICAL: El icono '${manifest.metadata.icon}' no existe en el catálogo de recursos.`,
            keyword: 'era7_asset_critical',
            severity: 'critical'
        });
    }

    containers.forEach((c, idx) => {
        if (c.asset && !availableAssets.has(c.asset)) {
            issues.push({
                path: `/ui/layout/containers/${idx}/asset`,
                message: `CRITICAL: El fondo '${c.asset}' para '${c.id}' no existe.`,
                keyword: 'era7_asset_critical',
                severity: 'critical'
            });
        }
    });

    const validateEntity = (entity: ManifestEntity, path: string) => {
      const containerId = entity.presentation?.container;
      const container = containers.find(c => c.id === containerId);
      const entityTab = container?.tab || 'MAIN';

      // ERA 7.2.3 - MANDATORY ASSOCIATION
      if (!containerId) {
        issues.push({
          path: `${path}/presentation/container`,
          message: `CRITICAL: El elemento '${entity.id}' no tiene contenedor asociado. Todas las cells deben pertenecer a una placa base.`,
          keyword: 'era7_orphan_cell',
          severity: 'error'
        });
      } else if (!container) {
        issues.push({
          path: `${path}/presentation/container`,
          message: `CRITICAL: El contenedor '${containerId}' referenciado por '${entity.id}' no existe.`,
          keyword: 'era7_broken_link',
          severity: 'error'
        });
      }

      // ERA 7.2.3 - PLANE INTEGRITY
      if (container && !activePlanes.includes(entityTab as string)) {
        issues.push({
          path: `${path}/presentation/container`,
          message: `CRITICAL: '${entity.id}' está en un contenedor asignado al plano '${entityTab}', pero este plano no está activo en el módulo.`,
          keyword: 'era7_plane_leak',
          severity: 'error'
        });
      }

      // Asset Validation (Fase 13 — AGGRESSIVE)
      const assetId = entity.presentation.asset;
      const isLogo = entity.bind === 'module_logo' || entity.id === 'logo';

      if ((assetId || isLogo) && !availableAssets.has(assetId || '')) {
          issues.push({
              path: `${path}/presentation/asset`,
              message: `CRITICAL ASSET: El recurso '${assetId || 'module_logo'}' referenciado por '${entity.id}' no existe en el manifiesto.`,
              keyword: 'era7_asset_critical',
              severity: 'critical'
          });
      }

      // Golden Rule 1: Identity
      if (usedIds.has(entity.id)) {
        issues.push({ path: `${path}/id`, message: `DOUBLE IDENTITY: ID '${entity.id}' duplicado.`, keyword: 'era7_identity', severity: 'error' });
      }
      usedIds.add(entity.id);

      // Pro-Master: Rule of 5px
      if (entity.pos.x % 5 !== 0 || entity.pos.y % 5 !== 0) {
        issues.push({
          path: `${path}/pos`,
          message: `PRO-MASTER: Desalineado. La posición (${entity.pos.x}, ${entity.pos.y}) debe ser múltiplo de 5 (Regla de los 5px).`,
          keyword: 'era7_alignment',
          severity: 'audit'
        });
      }

      // Pro-Master: Port Normalization
      if (path.includes('/jacks/')) {
        const color = entity.presentation?.color;
        if (!color) {
          issues.push({
            path: `${path}/presentation/color`,
            message: `PRO-MASTER: Puerto sin color. Usa B_cyan (Audio/CV), neon_amber (Mod), white (Gate) u orange (MIDI).`,
            keyword: 'era7_port_norm',
            severity: 'audit'
          });
        }
      }

      // Pro-Master: Missing Units
      const isIndicator = entity.role === 'telemetry' || entity.presentation?.component === 'led' || entity.presentation?.component === 'display';
      const isMidiOrString = entity.type === 'string' || manifest.metadata?.family === 'midi';
      if (!entity.unit && entity.role !== 'output' && !isIndicator && !isMidiOrString) {
        issues.push({ path: `${path}/unit`, message: `PRO-MASTER: Falta unidad (Hz, dB, ms, semi, %). Requerido para parámetros de control.`, keyword: 'era7_ux', severity: 'audit' });
      }

      // Advanced: Out of Bounds
      if (entity.pos.x < 0 || entity.pos.x > rackWidth || entity.pos.y < 0 || entity.pos.y > rackHeight) {
        issues.push({ path: `${path}/pos`, message: `OUT OF BOUNDS: '${entity.id}' fuera del metal.`, keyword: 'era7_integrity', severity: 'error' });
      }

      // Advanced: Orphan Binds
      if (contract && entity.bind) {
        const cleanBind = String(entity.bind).trim().toLowerCase();
        const allBinds = [
          ...(contract.parameters?.map(p => String(p.id).trim().toLowerCase()) || []),
          ...(contract.ports?.map(p => String(p.id).trim().toLowerCase()) || [])
        ];

        if (!allBinds.includes(cleanBind)) {
          issues.push({ 
            path: `${path}/bind`, 
            message: `ORPHAN BIND: '${entity.bind}' no existe en el contrato WASM.`, 
            keyword: 'era7_binding', 
            severity: 'error' 
          });
        }
      }

      // Pro-Master: Overlapping & Ergonomics
      const allEntities = [
        ...(manifest.ui?.controls || []),
        ...(manifest.ui?.jacks || [])
      ];

      allEntities.forEach((other) => {
        if (entity.id === other.id) return;

        const otherTab = containerTabMap.get(other.presentation?.container || 'STATUS') || 'MAIN';
        if (entityTab !== otherTab) return;

        const dist = Math.sqrt(Math.pow(entity.pos.x - other.pos.x, 2) + Math.pow(entity.pos.y - other.pos.y, 2));
        if (dist < 5) {
          issues.push({ path: `${path}/pos`, message: `PRO-MASTER: Colisión crítica con '${other.id}'. Componentes solapados en pestaña '${entityTab}'.`, keyword: 'era7_collision', severity: 'error' });
        }
      });

      // Pro-Master: Unit Consistency
      const label = (entity.label || '').toLowerCase();
      if ((label.includes('freq') || label.includes('cut') || label.includes('pich')) && entity.unit !== 'Hz' && entity.unit !== 'kHz' && entity.unit !== 'semi') {
        issues.push({ path: `${path}/unit`, message: `PRO-MASTER: Consistencia de unidades. Parámetro tonal detectado, se recomienda 'Hz' o 'semi'.`, keyword: 'era7_ux_context', severity: 'audit' });
      }
    };

    (manifest.ui?.controls || []).forEach((e, idx) => validateEntity(e, `/ui/controls/${idx}`));
    (manifest.ui?.jacks || []).forEach((e, idx) => validateEntity(e, `/ui/jacks/${idx}`));

    return issues;
  }
}

import AJV, { ErrorObject } from 'ajv';
import addFormats from 'ajv-formats';
import era6Schema from '../../data/omega-schema.json';
import era7Schema from '../../data/omega-schema-v7.json';
import { ValidationIssue } from '../../types/validation';
import { OMEGA_Manifest } from '../../omega-ui-core/types/manifest';

const ajv = new AJV({ 
  allErrors: true,
  strict: false,
  verbose: true
});

addFormats(ajv);

const validateV6 = ajv.compile(era6Schema);
const validateV7 = ajv.compile(era7Schema);

export class SchemaValidator {
  static validate(manifest: OMEGA_Manifest): ValidationIssue[] {
    const isV7 = manifest.schemaVersion?.startsWith('7') || manifest.schemaVersion === '7.0';
    const validator = isV7 ? validateV7 : validateV6;

    validator(manifest);

    return (validator.errors || []).map((err: ErrorObject) => {
      let message = err.message || 'Invalid value';

      if (err.keyword === 'additionalProperties') {
        const prop = err.params?.additionalProperty;
        message = `Unrecognized property found: '${prop}'. Remove it to satisfy OMEGA compliance.`;
      }

      if (err.keyword === 'enum') {
        const allowed = err.params?.allowedValues?.join(', ');
        message = `Invalid choice. Expected one of: [${allowed}]`;
      }

      if (err.keyword === 'type') {
        message = `Data type mismatch. Expected ${err.params?.type} but found something else.`;
      }

      return {
        path: err.instancePath || '',
        message: message,
        keyword: err.keyword || 'schema',
        severity: 'error'
      };
    });
  }
}

import { OMEGA_Manifest } from '../types/manifest';
import { OmegaContract } from './wasmLoader';
import { ValidationIssue } from '../types/validation';
import { SchemaValidator } from './validation/schemaValidator';
import { IndustrialRules } from './validation/industrialRules';

export class ValidationService {
  /**
   * Orchestrates the complete validation pipeline (Schema + Industrial Rules).
   */
  static validate(manifest: OMEGA_Manifest, contract: OmegaContract | null = null): ValidationIssue[] {
    // 1. Technical Schema Validation (AJV)
    const schemaIssues = SchemaValidator.validate(manifest);

    // 2. Industrial/Business Rules (Era 7)
    const industrialIssues = IndustrialRules.validate(manifest, contract);

    return [...schemaIssues, ...industrialIssues];
  }
}

/**
 * OMEGA WASM Loader Service
 * Handles instantiation and contract extraction from self-descriptive WASM modules.
 */

export interface OmegaContract {
  omega_version: string;
  id: string;
  name?: string;
  family?: string;
  parameters: Array<{
    id: string;
    name: string;
    min: number;
    max: number;
    default: number;
    unit?: string;
  }>;
  ports: Array<{
    id: string;
    type: 'audio' | 'cv' | 'midi' | 'gate';
    direction: 'input' | 'output';
  }>;
  firmwareHash?: string;
}

export class WasmLoaderService {
  /**
   * Loads a WASM file and attempts to call 'omega_get_contract'
   */
  static async extractContract(file: File): Promise<OmegaContract> {
    const arrayBuffer = await file.arrayBuffer();

    // Create a robust import object using a Proxy to catch all OMEGA host functions
    const hostFunctions: Record<string, WebAssembly.ImportValue> = {
      memory: new WebAssembly.Memory({ initial: 256, maximum: 512 }),
      abort: () => console.warn('[WASM] Abort called'),
      // Standard OMEGA host functions that might be called during static init
      omega_log: (ptr: number) => console.log('[WASM LOG] Pointer:', ptr),
    };

    const importObject: WebAssembly.Imports = {
      env: new Proxy(hostFunctions, {
        get(target: Record<string, WebAssembly.ImportValue>, prop: string): WebAssembly.ImportValue | undefined {
          if (prop in target) return target[prop];

          // Return a dummy callable for any requested OMEGA host function (omega_...)
          if (prop.startsWith('omega_')) {
            console.debug(`[WASM-LINK] Providing dummy for missing host function: ${prop}`);
            return () => 0; 
          }

          return undefined;
        }
      })
    };

    try {
      const { instance } = await WebAssembly.instantiate(arrayBuffer, importObject);
      const exports = instance.exports as { 
        omega_get_contract?: () => number;
        memory?: WebAssembly.Memory;
      };

      if (!exports.omega_get_contract) {
        throw new Error("WASM module is not OMEGA-compliant (missing 'omega_get_contract' export).");
      }

      // Call the function to get the pointer to the JSON string
      const ptr = exports.omega_get_contract();

      // Read the string from WASM memory
      const memory = exports.memory || (hostFunctions.memory as WebAssembly.Memory);
      const jsonString = this.readStringFromMemory(memory, ptr);
      const raw = JSON.parse(jsonString);
      const data = raw.contract || raw;

      // Normalization for Era 7.1 consistency
      const contract: OmegaContract = {
        omega_version: data.omega_version || data.version || "7.0",
        id: String(data.id || 'unknown'),
        name: data.name || data.id,
        family: (data.family || "utility").toLowerCase(),
        parameters: (data.parameters || []).map((p: { id?: string; name?: string; min?: number; max?: number; default?: number; unit?: string }) => ({
          id: String(p.id || p.name || '').toLowerCase(),
          name: p.name || p.id || 'unknown',
          min: p.min ?? 0,
          max: p.max ?? 1,
          default: p.default ?? 0,
          unit: p.unit
        })),
        ports: (data.ports || []).map((p: { id?: string; name?: string; type?: string; direction?: string }) => ({
          id: String(p.id || p.name || '').toLowerCase(),
          type: (p.type || 'audio') as 'audio' | 'cv' | 'midi' | 'gate',
          direction: (p.direction || 'input') as 'input' | 'output'
        }))
      };

      return contract;
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      console.error("Failed to extract OMEGA contract:", message);
      throw new Error(`LinkError: Binary requires host functions or is corrupted. Details: ${message}`);
    }
  }

  private static readStringFromMemory(memory: WebAssembly.Memory, ptr: number): string {
    const view = new Uint8Array(memory.buffer);
    let end = ptr;
    while (view[end] !== 0 && end < view.length) end++; // Null-terminated string

    const decoder = new TextDecoder();
    return decoder.decode(view.slice(ptr, end));
  }
}

/**
 * OMEGA WASM BRIDGE - ERA 7.1
 * Interface for real-time DSP simulation within the Manifest Editor.
 */

import { OMEGA_Manifest } from '../types/manifest';
import { inputSignalService } from './inputSignalService';

export interface WasmInterface {
  init: () => void;
  process: (inputBuffer: Float32Array, outputBuffer: Float32Array) => void;
  setParameter: (id: string, value: number) => void;
  getTelemetry: (id: string) => number;
}

export class WasmRuntime {
  private instance: WebAssembly.Instance | null = null;
  private isMock: boolean = true;
  private mockValues: Record<string, number> = {};

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  async loadWasm(buffer: ArrayBuffer): Promise<boolean> {
    try {
      // En un entorno real, aquí instanciaríamos el WASM con los imports de OMEGA
      // const { instance } = await WebAssembly.instantiate(buffer, { env: { ... } });
      // this.instance = instance;
      this.isMock = false;
      console.log('OMEGA WASM: Binario cargado y listo para ejecución.');
      return true;
    } catch (e) {
      console.error('OMEGA WASM: Error al instanciar el binario.', e);
      return false;
    }
  }

  setParameter(id: string, value: number) {
    if (this.isMock) {
      this.mockValues[id] = value;
      return;
    }
    // Lógica para escribir en la memoria lineal del WASM
    if (this.instance) {
       // logic here
    }
  }

  getTelemetry(id: string): number {
    if (this.isMock) {
      // Si hay una señal de entrada en este ID (ej: un port), la usamos como base para la telemetría
      const inputVal = inputSignalService.getSignalValue(id);

      // Simulación de respuesta dinámica: la telemetría reacciona a los inputs + un pequeño offset de ruido
      return inputVal + (this.mockValues[id] || 0) + (Math.sin(Date.now() / 1000) * 0.05);
    }
    // Lógica real para WASM...
    return 0;
  }

  async deployManifest(manifest: OMEGA_Manifest): Promise<{ success: boolean; hash: string }> {
    console.log(`OMEGA HIL: Desplegando manifiesto '${manifest.id}' v${manifest.schemaVersion}...`);

    // Simulación de latencia de red/carga en hardware real
    await new Promise(resolve => setTimeout(resolve, 800));

    // En un entorno real, aquí se enviaría el manifiesto vía RPC o SharedArrayBuffer
    // Por ahora, simulamos la generación de un hash de integridad del firmware
    const hash = Math.random().toString(16).slice(2, 10).toUpperCase();

    return { 
      success: true, 
      hash 
    };
  }

  // Activa un modo "Demo" que hace que la telemetría se mueva
  enableDemoMode() {
    this.isMock = true;
  }
}

